window.KEMTID_DATA.quizzes.push(
  {"id":"q_tpat3_pattern1","subjectId":"tpat3","title":"TPAT3 · ด้านตัวเลข: รูปแบบลำดับและการดำเนินการที่กำหนดเอง","topic":"Numerical Reasoning (Number Patterns & Custom Operations)","difficulty":"ยาก","intro":{"concept":"โจทย์ด้านตัวเลขของ TPAT3 จริงมีสัดส่วนสำคัญเป็นโจทย์ 'นิยามการดำเนินการขึ้นเอง' (เช่น a@b = ...) ที่ต้องหาสูตรความสัมพันธ์จากตัวอย่างที่ให้มาก่อน แล้วนำสูตรนั้นไปใช้กับค่าใหม่ — ต่างจากลำดับตัวเลขทั่วไปตรงที่มีสัญลักษณ์แปลกใหม่ ต้องอ่านตัวอย่างให้ครบก่อนเดาสูตร","worked":{"q":"กำหนด a @ b = 2a + b เมื่อ 1 @ 2 = 4 และ 2 @ 1 = 5 จงหา 5 @ 3","steps":["ตรวจสอบสูตรกับตัวอย่างแรก: 1@2 = 2(1)+2 = 4 ✓","ตรวจสอบกับตัวอย่างที่สอง: 2@1 = 2(2)+1 = 5 ✓","สูตรถูกต้อง แทนค่า 5@3 = 2(5)+3 = 13"],"answer":"13"}},"questions":[{"q":"ลำดับ 1, 1, 2, 3, 5, 8, ? พจน์ถัดไปคือเท่าใด","choices":["11","12","13","15"],"correct":2,"hint":"ลองสังเกตว่าพจน์แต่ละตัวสัมพันธ์กับสองพจน์ก่อนหน้าอย่างไร","steps":["สังเกตว่า 2=1+1, 3=1+2, 5=2+3, 8=3+5","รูปแบบคือ พจน์ถัดไป = ผลบวกของสองพจน์ก่อนหน้า (ลำดับฟีโบนัชชี)","พจน์ถัดไป = 5+8 = 13"],"tip":"ลำดับที่แต่ละพจน์มาจากผลบวกของสองพจน์ก่อนหน้าเรียกว่าลำดับฟีโบนัชชี เป็นรูปแบบยอดฮิตที่ออกสอบบ่อย"},{"q":"ลำดับ 2, 6, 12, 20, 30, ? พจน์ถัดไปคือเท่าใด","choices":["38","40","42","44"],"correct":2,"hint":"ลองหาผลต่างระหว่างพจน์ที่ติดกันดูว่าผลต่างนั้นเปลี่ยนแปลงอย่างไร","steps":["หาผลต่างระหว่างพจน์: 6−2=4, 12−6=6, 20−12=8, 30−20=10","ผลต่างเพิ่มขึ้นทีละ 2 (4,6,8,10,...)","ผลต่างถัดไปคือ 12","พจน์ถัดไป = 30+12 = 42"],"tip":"เมื่อผลต่างชั้นแรกไม่คงที่ ให้ลองหาผลต่างของผลต่าง (ผลต่างชั้นสอง) จะช่วยเห็นรูปแบบได้ชัดขึ้น"},{"q":"กำหนด a @ b = 2a + b เมื่อ 1 @ 2 = 4 และ 2 @ 1 = 5 จงหาค่าของ 5 @ 3","choices":["11","12","13","14"],"correct":2,"hint":"ตรวจสอบสูตรที่ให้มากับตัวอย่างทั้งสองก่อน แล้วแทนค่าใหม่ลงในสูตรเดียวกัน","steps":["สูตรที่กำหนดคือ a@b = 2a+b","แทนค่า a=5, b=3","คำนวณ 2(5)+3 = 10+3","ผลลัพธ์ = 13"],"tip":"โจทย์แบบนี้ให้สูตรมาตรงๆ แล้ว บางครั้งไม่ต้องเดาสูตรเอง แค่แทนค่าตามสูตรที่ให้ให้ถูกต้องก็พอ — อ่านโจทย์ให้ครบว่าให้สูตรมาหรือให้แค่ตัวอย่าง"},{"q":"กำหนดการดำเนินการ a ♦ b = a² − b เมื่อ 3 ♦ 2 = 7 และ 4 ♦ 1 = 15 จงหาค่าของ 5 ♦ 2","choices":["18","20","21","23"],"correct":3,"hint":"ตรวจสอบสูตร a²−b กับตัวอย่างทั้งสองก่อน แล้วแทนค่าใหม่","steps":["ตรวจสอบสูตรกับตัวอย่างแรก: 3♦2 = 3²−2 = 9−2 = 7 ✓","ตรวจสอบกับตัวอย่างที่สอง: 4♦1 = 4²−1 = 16−1 = 15 ✓","สูตรคือ a♦b = a²−b แทนค่า 5♦2 = 5²−2 = 25−2","ผลลัพธ์ = 23"],"tip":"โจทย์นิยามการดำเนินการเองมักซ่อนการยกกำลังหรือการคูณไว้ในสูตร ลองทดสอบสูตรที่ซับซ้อนขึ้น (เช่น a², a×b) ถ้าสูตรบวก-ลบธรรมดาไม่ตรงกับตัวอย่างที่ให้มา"}]},
  {"id":"q_tpat3_word1","subjectId":"tpat3","title":"TPAT3 · ด้านตัวเลข: โจทย์สถานการณ์","topic":"Numerical Reasoning (สัดส่วน เปอร์เซ็นต์ อัตราส่วนผกผัน)","difficulty":"ยาก","intro":{"concept":"นอกจากโจทย์แนวรูปแบบ/สัญลักษณ์แล้ว TPAT3 ยังมีโจทย์สถานการณ์จริง (อัตราส่วนต่อเนื่อง สัดส่วนผกผัน เปอร์เซ็นต์) ปนอยู่ด้วย เทคนิคคือตั้งสมการจากสิ่งที่โจทย์ให้มาก่อนคำนวณเสมอ อย่าเดาจากความรู้สึก","worked":{"q":"ถ้า A:B = 2:3 และมี A รวม 10 หน่วย จะมี B กี่หน่วย","steps":["จากอัตราส่วน A:B = 2:3 หมายความว่า A มี 2 ส่วน B มี 3 ส่วน","ถ้า A = 10 หน่วย แสดงว่า 1 ส่วน = 10÷2 = 5 หน่วย","B = 3 ส่วน × 5 = 15 หน่วย"],"answer":"15 หน่วย"}},"questions":[{"q":"ถ้า A:B = 3:5 และ B:C = 2:3 แล้ว A:B:C มีอัตราส่วนเท่าใด","choices":["6:10:15","3:5:3","6:5:15","3:10:15"],"correct":0,"hint":"ต้องทำให้ค่า B ในสองอัตราส่วนเท่ากันก่อน โดยหา ค.ร.น. ของ 5 กับ 2","steps":["A:B = 3:5 และ B:C = 2:3 ต้องทำ B ให้เท่ากันก่อน","ค.ร.น. ของ 5 และ 2 คือ 10","ขยาย A:B = 3:5 เป็น 6:10 (คูณ 2) และ B:C = 2:3 เป็น 10:15 (คูณ 5)","รวมได้ A:B:C = 6:10:15"],"tip":"โจทย์อัตราส่วนต่อเนื่อง (A:B และ B:C) ต้องทำตัวร่วม (B) ให้เท่ากันก่อนเสมอ ถึงจะรวมเป็นอัตราส่วนเดียวได้"},{"q":"พนักงาน 5 คน ทำงานชิ้นหนึ่งเสร็จใน 12 วัน ถ้าเพิ่มพนักงานเป็น 10 คน (อัตราทำงานเท่าเดิมต่อคน) จะทำงานชิ้นเดียวกันเสร็จในกี่วัน","choices":["3 วัน","6 วัน","10 วัน","24 วัน"],"correct":1,"hint":"งานทั้งหมดคงที่ ถ้าคนเพิ่มขึ้นเป็น 2 เท่า เวลาที่ใช้ควรเปลี่ยนไปในทิศทางตรงข้าม","steps":["ปริมาณงานทั้งหมด = จำนวนคน × จำนวนวัน = 5×12 = 60 หน่วยงาน-วัน","เมื่อมีคนงาน 10 คน จำนวนวันที่ใช้ = 60÷10","คำนวณ = 6 วัน"],"tip":"โจทย์แบบนี้เป็นสัดส่วนผกผัน (คนมากขึ้น เวลาน้อยลง) ต่างจากสัดส่วนตรงที่ทั้งสองค่าเพิ่มไปด้วยกัน ต้องแยกให้ออก"},{"q":"ยอดขายเพิ่มขึ้นจาก 200 หน่วย เป็น 250 หน่วย เพิ่มขึ้นกี่เปอร์เซ็นต์","choices":["20%","25%","30%","50%"],"correct":1,"hint":"หาจำนวนที่เพิ่มขึ้นก่อน แล้วเทียบเป็นสัดส่วนกับค่าตั้งต้น (200) ไม่ใช่ค่าใหม่","steps":["จำนวนที่เพิ่มขึ้น = 250−200 = 50 หน่วย","เปอร์เซ็นต์ที่เพิ่ม = (ส่วนที่เพิ่ม/ค่าตั้งต้น)×100","แทนค่า = (50/200)×100 = 25%"],"tip":"เปอร์เซ็นต์การเปลี่ยนแปลงเทียบกับค่าตั้งต้นเสมอ ไม่ใช่ค่าสุดท้าย เป็นจุดที่พลาดกันบ่อยที่สุดในโจทย์แนวนี้"},{"q":"โรงงาน A ผลิตสินค้าได้ 40 ชิ้นต่อชั่วโมง โรงงาน B ผลิตได้น้อยกว่า A อยู่ 25% โรงงาน B จะผลิตสินค้าได้กี่ชิ้นใน 5 ชั่วโมง","choices":["120 ชิ้น","140 ชิ้น","150 ชิ้น","160 ชิ้น"],"correct":2,"hint":"หาอัตราการผลิตของ B ต่อชั่วโมงก่อน แล้วค่อยคูณด้วยจำนวนชั่วโมง","steps":["อัตราของ A = 40 ชิ้น/ชั่วโมง","B น้อยกว่า A อยู่ 25% → อัตราของ B = 40×0.75 = 30 ชิ้น/ชั่วโมง","ใน 5 ชั่วโมง B ผลิตได้ = 30×5","คำนวณ = 150 ชิ้น"],"tip":"โจทย์ 'น้อยกว่า X%' ให้คูณด้วย (1−X/100) ไม่ใช่ลบตรงๆ เป็นจุดที่พลาดกันบ่อย เหมือนกับ 'มากกว่า X%' ที่ต้องคูณด้วย (1+X/100)"}]},
  {"id":"q_tpat3_mech1","subjectId":"tpat3","title":"TPAT3 · ด้านกลศาสตร์: เครื่องกลอย่างง่าย","topic":"Mechanical Reasoning (Simple Machines)","difficulty":"กลาง","intro":{"concept":"โจทย์กลุ่มนี้ทดสอบสามัญสำนึกเชิงกลศาสตร์ ไม่ต้องคำนวณซับซ้อน แค่เข้าใจหลักการของเครื่องกลอย่างง่าย (รอก คาน เฟือง ล้อและเพลา) ว่าแต่ละแบบช่วยผ่อนแรงหรือเปลี่ยนทิศทางแรงอย่างไร","worked":{"q":"รอกเดี่ยวตายตัว (fixed pulley) ช่วยผ่อนแรงได้หรือไม่","steps":["รอกเดี่ยวตายตัวเปลี่ยนเพียงทิศทางของแรงเท่านั้น ไม่ได้เพิ่มระยะที่เชือกพันรอบวัตถุ","แรงที่ใช้ดึงเท่ากับน้ำหนักวัตถุพอดี (mechanical advantage = 1)","ดังนั้นรอกเดี่ยวตายตัวไม่ช่วยผ่อนแรง ช่วยแค่เปลี่ยนทิศทาง"],"answer":"ไม่ผ่อนแรง เปลี่ยนแค่ทิศทาง"}},"questions":[{"q":"รอกเดี่ยวเคลื่อนที่ได้ (movable pulley) ในอุดมคติ ช่วยผ่อนแรงได้กี่เท่าเมื่อเทียบกับการยกน้ำหนักโดยตรง","choices":["1 เท่า","2 เท่า","3 เท่า","4 เท่า"],"correct":1,"hint":"รอกเคลื่อนที่ได้มีเชือก 2 เส้นช่วยรับน้ำหนักวัตถุ ลองคิดว่าแรงที่ต้องออกจะลดลงกี่เท่า","steps":["รอกเคลื่อนที่ได้มีเส้นเชือก 2 เส้นรับน้ำหนักวัตถุพร้อมกัน","แรงที่ใช้ดึงจึงเหลือเพียงครึ่งหนึ่งของน้ำหนักวัตถุ","หมายความว่าผ่อนแรงได้ 2 เท่า (ในอุดมคติ ไม่คิดแรงเสียดทาน)"],"tip":"หลักจำง่ายๆ: นับจำนวนเส้นเชือกที่รับน้ำหนักวัตถุโดยตรง จำนวนนั้นคือตัวเลขที่ผ่อนแรงได้"},{"q":"เฟือง A มีฟัน 20 ซี่ ขบกับเฟือง B ที่มีฟัน 40 ซี่ ถ้าเฟือง A หมุน 4 รอบ เฟือง B จะหมุนกี่รอบ","choices":["1 รอบ","2 รอบ","4 รอบ","8 รอบ"],"correct":1,"hint":"เฟืองที่มีฟันเยอะกว่าจะหมุนช้ากว่า ลองตั้งสัดส่วนจำนวนฟันเทียบกับจำนวนรอบ","steps":["เฟืองที่ขบกันมีจำนวนฟันที่ผ่านจุดขบเท่ากันเสมอ","จำนวนรอบ B = จำนวนรอบ A × (ฟัน A / ฟัน B)","แทนค่า = 4 × (20/40)","คำนวณ = 2 รอบ"],"tip":"เฟืองใหญ่ (ฟันเยอะ) หมุนช้ากว่าเฟืองเล็กเสมอเมื่อขบกันโดยตรง จำทิศทางความสัมพันธ์นี้ไว้ตอบเร็วๆ ได้"},{"q":"คานงัดชนิดที่ 1 (จุดหมุนอยู่ระหว่างแรงพยายามกับแรงต้าน) ถ้าระยะจากจุดหมุนถึงจุดออกแรงยาวกว่าระยะจากจุดหมุนถึงแรงต้าน จะเป็นอย่างไร","choices":["ผ่อนแรง ใช้แรงน้อยลง","ไม่ผ่อนแรง ใช้แรงเท่าเดิม","ต้องใช้แรงมากขึ้น","ไม่เกี่ยวข้องกับระยะ"],"correct":0,"hint":"คานงัดผ่อนแรงได้เมื่อระยะด้านที่ออกแรงยาวกว่าระยะด้านที่ต้านแรง ลองนึกถึงชะแลงงัดของหนัก","steps":["หลักโมเมนต์: แรงพยายาม × ระยะจากจุดหมุนถึงจุดออกแรง = แรงต้าน × ระยะจากจุดหมุนถึงแรงต้าน","ถ้าระยะด้านออกแรงยาวกว่า แรงพยายามที่ต้องใช้ก็จะน้อยกว่าแรงต้าน","จึงสรุปได้ว่าผ่อนแรง ใช้แรงน้อยลง"],"tip":"หลักการนี้เหมือนชะแลงงัดหิน — จับด้ามยาวๆ ให้ห่างจากจุดหมุนมากๆ จะงัดของหนักได้ง่ายขึ้น"},{"q":"ล้อและเพลา (wheel and axle) เช่น พวงมาลัยรถยนต์ ช่วยผ่อนแรงได้เพราะเหตุใด","choices":["เพราะล้อมีรัศมีใหญ่กว่าเพลา ทำให้แรงที่ขอบล้อน้อยกว่าแรงที่เพลาต้องใช้","เพราะเพลาหมุนเร็วกว่าล้อเสมอ","เพราะล้อไม่มีแรงเสียดทานเลย","เพราะเพลามีมวลมากกว่าล้อ"],"correct":0,"hint":"เปรียบเทียบรัศมีของล้อ (จุดที่ออกแรง) กับรัศมีของเพลา (จุดที่ต้านแรง) ตามหลักโมเมนต์","steps":["ล้อและเพลาทำงานเหมือนคานงัดที่หมุนรอบแกนเดียวกัน","เทียบรัศมีล้อ (ใหญ่) กับรัศมีเพลา (เล็ก) ตามหลักโมเมนต์","แรงที่ขอบล้อ × รัศมีล้อ = แรงที่เพลา × รัศมีเพลา","เมื่อรัศมีล้อใหญ่กว่า แรงที่ต้องออกที่ขอบล้อจึงน้อยกว่า"],"tip":"พวงมาลัยรถ ลูกบิดประตู ก๊อกน้ำ ล้วนใช้หลักล้อและเพลาเพื่อผ่อนแรงแบบเดียวกันนี้"}]},
  {"id":"q_tpat3_mech2","subjectId":"tpat3","title":"TPAT3 · ด้านกลศาสตร์และฟิสิกส์: ความรู้เชิงมโนทัศน์","topic":"Mechanical & Physics Aptitude (Circuits & Matter)","difficulty":"กลาง","intro":{"concept":"ตัวอย่างข้อสอบจริงจากสถาบันติวชื่อดังแสดงว่าหมวดนี้ไม่ได้มีแค่โจทย์คำนวณเครื่องกล แต่มีโจทย์ความรู้เชิงมโนทัศน์ด้านวงจรไฟฟ้าและสมบัติของสสารปนอยู่ด้วย — ไม่ต้องคำนวณ แค่เข้าใจหลักการพื้นฐานให้แม่น","worked":{"q":"เมื่อต่อหลอดไฟสองดวงแบบอนุกรม (series) แล้วหลอดหนึ่งขาด อีกหลอดหนึ่งจะเป็นอย่างไร","steps":["วงจรอนุกรมมีเส้นทางกระแสไฟฟ้าเพียงเส้นเดียว","เมื่อหลอดหนึ่งขาด วงจรจะขาดตอน กระแสไฟฟ้าไหลผ่านไม่ได้เลย","หลอดที่เหลือจึงดับไปด้วย"],"answer":"ดับไปด้วย"}},"questions":[{"q":"สวิตช์เปิด-ปิดไฟในบ้านทั่วไปต่ออยู่ในวงจรลักษณะใดเพื่อให้ตัดไฟทั้งวงจรได้เมื่อปิดสวิตช์","choices":["วงจรอนุกรม (series)","วงจรขนาน (parallel)","วงจรผสม","ไม่ต่อกับวงจรใดเลย"],"correct":0,"hint":"สวิตช์ต้องอยู่บนเส้นทางเดียวที่กระแสไฟฟ้าไหลผ่านทั้งหมด ถึงจะตัดไฟได้ทั้งวงจรเมื่อเปิดสวิตช์","steps":["ถ้าสวิตช์ต่อแบบอนุกรม จะอยู่บนเส้นทางเดียวที่กระแสไฟฟ้าต้องไหลผ่าน","เมื่อเปิดสวิตช์ (ตัดวงจร ณ จุดนั้น) กระแสจะไหลผ่านไม่ได้เลยทั้งวงจร ไฟจึงดับหมด","ถ้าต่อแบบขนาน การตัดสวิตช์จุดเดียวจะไม่ตัดไฟทั้งวงจร เพราะกระแสยังไหลผ่านเส้นทางอื่นได้"],"tip":"หลักการนี้คือเหตุผลที่สวิตช์ไฟบ้านต้องต่ออนุกรมกับหลอดไฟเสมอ ไม่ใช่ต่อขนาน มิฉะนั้นจะปิดไฟไม่ได้"},{"q":"เมื่อให้ความร้อนแก่ก้อนน้ำแข็งอย่างต่อเนื่องจนถึงจุดเดือด สสารจะเปลี่ยนสถานะตามลำดับใด","choices":["ของแข็ง → แก๊ส → ของเหลว","ของแข็ง → ของเหลว → แก๊ส","ของเหลว → ของแข็ง → แก๊ส","แก๊ส → ของเหลว → ของแข็ง"],"correct":1,"hint":"นึกถึงกระบวนการต้มน้ำแข็งบนเตา ลำดับการเปลี่ยนสถานะเป็นอย่างไร","steps":["น้ำแข็ง (ของแข็ง) เมื่อได้รับความร้อนจะละลายกลายเป็นน้ำ (ของเหลว) ก่อน","เมื่อน้ำได้รับความร้อนต่อไปจนถึงจุดเดือด จะกลายเป็นไอน้ำ (แก๊ส)","ลำดับคือ ของแข็ง → ของเหลว → แก๊ส"],"tip":"ลำดับการเปลี่ยนสถานะเมื่อเพิ่มความร้อนเสมอคือ ของแข็ง→ของเหลว→แก๊ส (การหลอมเหลวแล้วการกลายเป็นไอ) เป็นลำดับที่ย้อนกลับไม่ได้โดยไม่ลดความร้อน"},{"q":"เพราะเหตุใดน้ำแข็งจึงลอยอยู่บนผิวน้ำแทนที่จะจมลง","choices":["น้ำแข็งมีความหนาแน่นน้อยกว่าน้ำในสถานะของเหลว","น้ำแข็งมีอุณหภูมิสูงกว่าน้ำ","น้ำแข็งมีน้ำหนักเบากว่าน้ำเสมอไม่ว่าปริมาตรเท่าใด","แรงลอยตัวไม่มีผลต่อน้ำแข็ง"],"correct":0,"hint":"การที่วัตถุจะลอยหรือจมขึ้นกับการเปรียบเทียบความหนาแน่นกับของไหลที่มันอยู่ ไม่ใช่น้ำหนักเพียงอย่างเดียว","steps":["วัตถุจะลอยได้เมื่อความหนาแน่นของวัตถุน้อยกว่าความหนาแน่นของของไหลที่อยู่รอบๆ","น้ำแข็งมีโครงสร้างโมเลกุลที่จัดเรียงห่างกว่าน้ำเหลว ทำให้มีความหนาแน่นน้อยกว่าน้ำเหลวประมาณ 9%","เมื่อความหนาแน่นน้อยกว่า น้ำแข็งจึงลอยอยู่บนผิวน้ำได้"],"tip":"น้ำเป็นสสารพิเศษที่ของแข็ง (น้ำแข็ง) มีความหนาแน่นน้อยกว่าของเหลว (น้ำ) ต่างจากสสารส่วนใหญ่ที่ของแข็งมักหนาแน่นกว่าของเหลวของตัวเอง"},{"q":"เมื่อต่อตัวต้านทานสองตัวแบบขนาน (parallel) เทียบกับต่อแบบอนุกรม (series) ด้วยตัวต้านทานชุดเดียวกัน ความต้านทานรวมแบบใดจะมีค่าน้อยกว่า","choices":["แบบขนานมีความต้านทานรวมน้อยกว่าเสมอ","แบบอนุกรมมีความต้านทานรวมน้อยกว่าเสมอ","ทั้งสองแบบมีความต้านทานรวมเท่ากันเสมอ","ขึ้นอยู่กับสีของสายไฟ"],"correct":0,"hint":"ลองนึกถึงว่าการต่อขนานเปิดเส้นทางให้กระแสไหลได้หลายเส้นทางพร้อมกัน จะทำให้ต้านทานรวมมากขึ้นหรือน้อยลง","steps":["การต่อแบบขนานเปิดเส้นทางให้กระแสไฟฟ้าไหลผ่านได้หลายเส้นทางพร้อมกัน","ยิ่งมีเส้นทางให้กระแสไหลมาก ความต้านทานรวมของวงจรยิ่งลดลง","ดังนั้นความต้านทานรวมแบบขนานจะน้อยกว่าแบบอนุกรมเสมอ (เมื่อใช้ตัวต้านทานชุดเดียวกัน)"],"tip":"หลักจำง่ายๆ: อนุกรม = ความต้านทานรวมมากขึ้น (บวกตรงๆ), ขนาน = ความต้านทานรวมน้อยลงเสมอ (น้อยกว่าตัวที่น้อยที่สุดในกลุ่มด้วยซ้ำ)"}]},
  {"id":"q_tpat3_sci1","subjectId":"tpat3","title":"TPAT3 · ความคิดเชิงวิศวกรรม: กระบวนการออกแบบ","topic":"Scientific & Engineering Thinking (Design Process)","difficulty":"ยาก","intro":{"concept":"โจทย์กลุ่มนี้ทดสอบ 'วิธีคิด' แบบวิศวกร — เน้นลำดับขั้นตอนของกระบวนการออกแบบเชิงวิศวกรรม (เข้าใจปัญหา → ออกแบบ → สร้างต้นแบบ → ทดสอบ) และหลักการทดลองพื้นฐาน (กลุ่มควบคุม, การทำซ้ำ) อ่านสถานการณ์ให้เข้าใจก่อนแล้วเลือกคำตอบที่สมเหตุสมผลที่สุด","worked":{"q":"นักเรียนต้องการทดสอบว่าปุ๋ยชนิดใหม่ช่วยให้พืชโตเร็วขึ้นจริงหรือไม่ ควรออกแบบการทดลองอย่างไร","steps":["ต้องมีต้นพืชกลุ่มที่ได้รับปุ๋ยใหม่ (กลุ่มทดลอง)","ต้องมีต้นพืชอีกกลุ่มที่ปลูกในสภาพเดียวกันทุกอย่างแต่ไม่ได้รับปุ๋ยใหม่ (กลุ่มควบคุม)","เปรียบเทียบการเจริญเติบโตของสองกลุ่มเพื่อสรุปผลของปุ๋ย"],"answer":"ต้องมีกลุ่มควบคุมเปรียบเทียบเสมอ"}},"questions":[{"q":"วิศวกรต้องการทดสอบความแข็งแรงของสะพานจำลองก่อนสร้างจริง ควรทำอย่างไรตามหลักวิศวกรรม","choices":["สร้างแบบจำลองขนาดเล็กและทดสอบรับน้ำหนักก่อนขยายเป็นขนาดจริง","สร้างสะพานจริงแล้วทดสอบเลย","ประเมินจากความรู้สึกโดยไม่ทดสอบ","คัดลอกแบบจากสะพานอื่นโดยไม่ตรวจสอบเงื่อนไขพื้นที่"],"correct":0,"hint":"คิดถึงหลักการ \"ทดลองขนาดเล็กก่อนขยายผล\" ที่ใช้กันทั่วไปในงานวิศวกรรม","steps":["การสร้างสะพานจริงก่อนทดสอบมีความเสี่ยงสูงและสิ้นเปลืองมาก","แบบจำลองขนาดเล็กช่วยทดสอบหลักการและพฤติกรรมโครงสร้างได้โดยความเสี่ยงต่ำ","เมื่อผลการทดสอบเป็นที่น่าพอใจจึงขยายเป็นขนาดจริง"],"tip":"หลักการนี้คือ \"การสร้างต้นแบบ (prototyping)\" ซึ่งเป็นขั้นตอนมาตรฐานของกระบวนการออกแบบเชิงวิศวกรรมทุกสาขา"},{"q":"ข้อใดคือขั้นตอนแรกของกระบวนการออกแบบเชิงวิศวกรรม (Engineering Design Process)","choices":["ระบุปัญหาและความต้องการให้ชัดเจน","สร้างต้นแบบทันที","ผลิตเป็นจำนวนมาก","ทดสอบผลิตภัณฑ์"],"correct":0,"hint":"ก่อนจะออกแบบหรือสร้างอะไร ต้องรู้ก่อนว่ากำลังแก้ปัญหาอะไรอยู่","steps":["กระบวนการออกแบบเชิงวิศวกรรมเริ่มจากการทำความเข้าใจปัญหาและความต้องการของผู้ใช้ก่อนเสมอ","ขั้นตอนถัดไปจึงเป็นการระดมความคิด ออกแบบ สร้างต้นแบบ และทดสอบตามลำดับ","การสร้างต้นแบบหรือผลิตทันทีโดยไม่เข้าใจปัญหาก่อนมักนำไปสู่การแก้ปัญหาผิดจุด"],"tip":"จำลำดับคร่าวๆ: เข้าใจปัญหา → ระดมความคิด → ออกแบบ → สร้างต้นแบบ → ทดสอบ → ปรับปรุง เป็นวงจรที่ใช้ได้กับงานวิศวกรรมแทบทุกประเภท"},{"q":"ในการทดลองทางวิทยาศาสตร์ การมี 'กลุ่มควบคุม' (control group) มีประโยชน์อย่างไร","choices":["ใช้เปรียบเทียบผลเพื่อยืนยันว่าตัวแปรที่ทดสอบเป็นสาเหตุของผลลัพธ์จริง","ทำให้การทดลองเสร็จเร็วขึ้น","ลดจำนวนตัวอย่างที่ต้องใช้ในการทดลอง","ไม่มีผลต่อความน่าเชื่อถือของการทดลอง"],"correct":0,"hint":"ลองนึกถึงการทดสอบยาใหม่ — ทำไมต้องมีกลุ่มที่ไม่ได้รับยาจริง (ได้ยาหลอก) มาเทียบด้วย","steps":["กลุ่มควบคุมคือกลุ่มที่ไม่ได้รับตัวแปรที่ต้องการทดสอบ แต่อยู่ในสภาพแวดล้อมเดียวกันทุกอย่าง","การเปรียบเทียบกลุ่มทดลองกับกลุ่มควบคุมช่วยแยกผลของตัวแปรที่สนใจออกจากปัจจัยอื่น","ทำให้สรุปได้อย่างมั่นใจว่าผลลัพธ์เกิดจากตัวแปรที่ทดสอบจริง ไม่ใช่ความบังเอิญ"],"tip":"หลักการนี้คือหัวใจของ \"วิธีการทางวิทยาศาสตร์\" (Scientific Method) ที่ข้อสอบเชิงความคิดชอบถามในรูปแบบสถานการณ์ต่างๆ"},{"q":"ถ้าผลการทดลองขัดแย้งกับสมมติฐานที่ตั้งไว้ นักวิทยาศาสตร์ควรทำอย่างไร","choices":["ทบทวนสมมติฐานหรือวิธีการทดลองใหม่ตามข้อมูลจริง","ปรับผลการทดลองให้ตรงกับสมมติฐาน","ยกเลิกการทดลองทั้งหมด","เพิกเฉยต่อผลที่ขัดแย้ง"],"correct":0,"hint":"วิธีการทางวิทยาศาสตร์ต้องยึดข้อมูลจริงเป็นหลัก ไม่ใช่ยึดความเชื่อเดิมที่ตั้งไว้","steps":["สมมติฐานเป็นเพียงการคาดเดาที่ต้องพิสูจน์ ไม่ใช่ข้อเท็จจริงที่แก้ไขไม่ได้","เมื่อข้อมูลจริงขัดแย้งกับสมมติฐาน ต้องทบทวนสมมติฐานหรือกระบวนการทดลองใหม่","การปรับแต่งผลให้ตรงกับสมมติฐานเดิมถือเป็นการทุจริตทางวิชาการ ไม่ใช่วิธีที่ถูกต้อง"],"tip":"หัวใจของวิธีการทางวิทยาศาสตร์คือการยึดข้อมูลจริงเป็นหลักเสมอ แม้ข้อมูลนั้นจะขัดกับสิ่งที่คาดไว้ก็ตาม"}]},
  {"id":"q_tpat3_sci2","subjectId":"tpat3","title":"TPAT3 · ความคิดเชิงวิทยาศาสตร์: ทำนายผลการทดลอง","topic":"Scientific Thinking (Predict Experimental Outcome)","difficulty":"ยาก","intro":{"concept":"ตัวอย่างข้อสอบจริงแสดงว่าโจทย์แนวนี้มักให้บรรยายการทดลองง่ายๆ แล้วถามให้ทำนายผลลัพธ์ (เช่น เจาะรูขวดน้ำที่ระดับความลึกต่างกัน น้ำจะพุ่งไกลเท่ากันหรือไม่) — ต้องอาศัยความเข้าใจหลักการทางวิทยาศาสตร์พื้นฐานจริงๆ ไม่ใช่แค่เดาสุ่ม","worked":{"q":"เจาะรูด้านข้างขวดน้ำพลาสติกที่ระดับความสูงต่างกัน 2 ตำแหน่ง (รูบนใกล้ปากขวด รูล่างใกล้ก้นขวด) แล้วเปิดฝา น้ำที่พุ่งออกจากรูล่างกับรูบนจะมีระยะพุ่งไกลต่างกันหรือไม่","steps":["ความดันของน้ำ ณ ตำแหน่งใดๆ ขึ้นกับความลึกของน้ำเหนือตำแหน่งนั้น (P = ρgh)","รูล่างอยู่ลึกกว่า จึงมีน้ำกดทับอยู่ด้านบนมากกว่า ความดันจึงสูงกว่า","ความดันที่สูงกว่าทำให้น้ำพุ่งออกด้วยความเร็วมากกว่า จึงพุ่งไกลกว่ารูบน"],"answer":"ต่างกัน รูล่างพุ่งไกลกว่าเพราะความดันน้ำสูงกว่า"}},"questions":[{"q":"ลูกบอลสองลูกขนาดเท่ากันแต่มวลต่างกันมาก ปล่อยจากที่สูงเดียวกันพร้อมกันในสุญญากาศ (ไม่มีแรงต้านอากาศ) ลูกใดจะตกถึงพื้นก่อน","choices":["ลูกที่มวลมากกว่าตกถึงพื้นก่อน","ลูกที่มวลน้อยกว่าตกถึงพื้นก่อน","ทั้งสองลูกตกถึงพื้นพร้อมกัน","ไม่สามารถทำนายได้เลย"],"correct":2,"hint":"ในสุญญากาศไม่มีแรงต้านอากาศมากวนผล ลองนึกถึงว่าความเร่งจากแรงโน้มถ่วงขึ้นอยู่กับมวลของวัตถุหรือไม่","steps":["ความเร่งจากแรงโน้มถ่วง (g) มีค่าเท่ากันสำหรับวัตถุทุกชนิด ไม่ขึ้นอยู่กับมวล","ในสุญญากาศไม่มีแรงต้านอากาศมารบกวนผลต่างระหว่างวัตถุ","วัตถุทั้งสองจึงมีความเร่งเท่ากันตลอดการตก และตกถึงพื้นพร้อมกัน"],"tip":"นี่คือการทดลองทางความคิดที่กาลิเลโอเคยเสนอ (และมีการทดลองจริงบนดวงจันทร์ยืนยัน) — มวลไม่มีผลต่อความเร็วการตกอิสระเมื่อไม่มีแรงต้านอากาศ"},{"q":"แก๊สในภาชนะปิดที่มีปริมาตรคงที่ ถ้าอุณหภูมิของแก๊สเพิ่มขึ้น ความดันของแก๊สจะเปลี่ยนแปลงอย่างไร","choices":["เพิ่มขึ้น","ลดลง","คงที่เสมอ","ไม่สามารถทำนายได้"],"correct":0,"hint":"อุณหภูมิที่สูงขึ้นทำให้โมเลกุลแก๊สเคลื่อนที่เร็วขึ้น ลองคิดว่าจะกระทบต่อการชนผนังภาชนะอย่างไร","steps":["เมื่ออุณหภูมิเพิ่มขึ้น โมเลกุลแก๊สจะมีพลังงานจลน์เฉลี่ยสูงขึ้น เคลื่อนที่เร็วขึ้น","โมเลกุลที่เคลื่อนที่เร็วขึ้นจะชนผนังภาชนะบ่อยขึ้นและแรงขึ้น","แรงชนที่มากขึ้นต่อหน่วยพื้นที่ทำให้ความดันของแก๊สเพิ่มขึ้น (ที่ปริมาตรคงที่)"],"tip":"หลักการนี้คือกฎของเกย์-ลูสแซก (Gay-Lussac's Law) — ที่ปริมาตรคงที่ ความดันแปรผันตรงกับอุณหภูมิสัมบูรณ์ของแก๊ส"},{"q":"ลูกตุ้มสองลูกที่มีความยาวเชือกต่างกัน (เชือกสั้น A และเชือกยาว B) ปล่อยให้แกว่งพร้อมกันจากมุมเบี่ยงเบนเท่ากัน ลูกใดจะแกว่งครบหนึ่งรอบเร็วกว่า","choices":["ลูก A (เชือกสั้น) แกว่งเร็วกว่า","ลูก B (เชือกยาว) แกว่งเร็วกว่า","ทั้งสองแกว่งครบรอบพร้อมกันเสมอ","ขึ้นอยู่กับน้ำหนักของลูกตุ้มเท่านั้น"],"correct":0,"hint":"คาบการแกว่งของลูกตุ้มขึ้นอยู่กับความยาวเชือก ไม่ได้ขึ้นอยู่กับน้ำหนักของลูกตุ้ม ลองคิดว่าเชือกสั้นกว่าน่าจะแกว่งเร็วหรือช้ากว่า","steps":["คาบการแกว่งของลูกตุ้มแปรผันตรงกับรากที่สองของความยาวเชือก (ไม่ขึ้นกับมวล)","เชือกที่สั้นกว่าจะมีคาบการแกว่งที่สั้นกว่า จึงแกว่งครบรอบเร็วกว่า","ลูก A (เชือกสั้น) จึงแกว่งครบหนึ่งรอบเร็วกว่าลูก B (เชือกยาว)"],"tip":"คาบลูกตุ้มไม่ขึ้นกับมวลหรือมุมเบี่ยงเบน (ที่มุมเล็กๆ) ขึ้นกับความยาวเชือกเท่านั้น เป็นจุดที่ข้อสอบชอบหลอกด้วยการเปลี่ยนน้ำหนักลูกตุ้มแทน"},{"q":"หยดสีผสมอาหารลงในแก้วน้ำร้อนกับแก้วน้ำเย็นพร้อมกัน (ไม่คน) แก้วใดสีจะกระจายตัวเร็วกว่า","choices":["แก้วน้ำร้อน เพราะโมเลกุลเคลื่อนที่เร็วกว่า","แก้วน้ำเย็น เพราะโมเลกุลเคลื่อนที่ช้ากว่าจึงกระจายเป็นระเบียบกว่า","กระจายตัวเร็วเท่ากันทั้งสองแก้ว","สีจะไม่กระจายตัวเลยถ้าไม่คน"],"correct":0,"hint":"อุณหภูมิสัมพันธ์กับพลังงานจลน์เฉลี่ยของโมเลกุล ลองคิดว่าโมเลกุลที่เคลื่อนที่เร็วกว่าจะช่วยให้การแพร่ (diffusion) เร็วขึ้นหรือช้าลง","steps":["การแพร่ (diffusion) ของสีในน้ำเกิดจากการเคลื่อนที่แบบสุ่มของโมเลกุลน้ำและโมเลกุลสี","น้ำร้อนมีโมเลกุลที่เคลื่อนที่เร็วกว่าน้ำเย็น (พลังงานจลน์เฉลี่ยสูงกว่า)","โมเลกุลที่เคลื่อนที่เร็วกว่าทำให้อัตราการแพร่เร็วขึ้น สีในน้ำร้อนจึงกระจายตัวเร็วกว่า"],"tip":"หลักการแพร่ (diffusion) นี้อธิบายได้ด้วยทฤษฎีจลน์ของสสาร (kinetic theory) เดียวกับที่ใช้อธิบายความดันแก๊สในข้อก่อนหน้า — อุณหภูมิสูง = โมเลกุลเคลื่อนที่เร็ว เป็นหลักการเชื่อมโยงกันทั้งหมด"}]},
  {"id":"q_tpat3_news1","subjectId":"tpat3","title":"TPAT3 · ความสนใจข่าวสาร: เทคโนโลยีปัจจุบัน","topic":"Science & Tech Literacy (Current Technology)","difficulty":"ง่าย","intro":{"concept":"ส่วนนี้ของจริงมักถามความรู้ข่าวสารเฉพาะช่วงเวลา (เช่น เหตุการณ์ที่เพิ่งเกิดขึ้น) ซึ่งเว็บนี้ไม่สามารถรักษาความทันสมัยต่อเนื่องได้ จึงเน้นความรู้เทคโนโลยีพื้นฐานที่ไม่ล้าสมัยแทน — ควรติดตามข่าวสารวิทยาศาสตร์-เทคโนโลยีปัจจุบันเพิ่มเติมด้วยตนเองก่อนสอบจริง (ดูลิงก์ข่าวสารในแท็บปฏิทิน)","worked":{"q":"พลังงานแสงอาทิตย์ (Solar Energy) จัดเป็นพลังงานประเภทใด","steps":["พลังงานแสงอาทิตย์มาจากดวงอาทิตย์ซึ่งมีแหล่งกำเนิดต่อเนื่องไม่มีวันหมด","จึงจัดอยู่ในกลุ่มพลังงานหมุนเวียน (Renewable Energy)"],"answer":"พลังงานหมุนเวียน"}},"questions":[{"q":"เทคโนโลยีปัญญาประดิษฐ์ประเภท Machine Learning เรียนรู้จากสิ่งใดเป็นหลัก","choices":["ข้อมูลตัวอย่างจำนวนมาก (data)","คำสั่งที่โปรแกรมเมอร์เขียนไว้ตายตัวทุกกรณี","การเดาสุ่มล้วนๆ โดยไม่มีข้อมูลอ้างอิง","สัญชาตญาณของเครื่องจักร"],"correct":0,"hint":"ชื่อ 'Machine Learning' บอกใบ้อยู่แล้วว่าเครื่องเรียนรู้จากอะไร ลองคิดถึงคำว่า 'เรียนรู้' ต้องใช้อะไรเป็นวัตถุดิบ","steps":["Machine Learning คือการให้คอมพิวเตอร์หารูปแบบ (pattern) จากข้อมูลตัวอย่างจำนวนมาก","ยิ่งมีข้อมูลมากและหลากหลาย โมเดลก็ยิ่งเรียนรู้และทำนายได้แม่นยำขึ้น","จึงต่างจากโปรแกรมทั่วไปที่เขียนกฎตายตัวไว้ล่วงหน้าทุกกรณี"],"tip":"แนวคิดนี้เป็นพื้นฐานสำคัญของสาย AI/Data ที่กำลังเป็นที่ต้องการมากในปัจจุบัน ควรเข้าใจให้แม่นถ้าสนใจสายนี้"},{"q":"ข้อใดไม่จัดอยู่ในกลุ่มพลังงานหมุนเวียน (Renewable Energy)","choices":["พลังงานแสงอาทิตย์","พลังงานลม","พลังงานจากถ่านหิน","พลังงานน้ำ"],"correct":2,"hint":"พลังงานหมุนเวียนคือพลังงานที่มีแหล่งกำเนิดทดแทนได้เร็วตามธรรมชาติ ลองคิดว่าตัวเลือกไหนใช้แล้วหมดไปและใช้เวลานับล้านปีกว่าจะเกิดใหม่","steps":["พลังงานแสงอาทิตย์ ลม และน้ำ ล้วนมีแหล่งกำเนิดต่อเนื่องตามธรรมชาติ ไม่มีวันหมด","ถ่านหินเป็นเชื้อเพลิงฟอสซิลที่เกิดจากซากสิ่งมีชีวิตทับถมนับล้านปี ใช้แล้วไม่สามารถสร้างทดแทนได้ทันในช่วงชีวิตมนุษย์","จึงจัดถ่านหินเป็นพลังงานสิ้นเปลือง ไม่ใช่พลังงานหมุนเวียน"],"tip":"จำกลุ่มพลังงานหมุนเวียนหลักไว้: แสงอาทิตย์ ลม น้ำ ความร้อนใต้พิภพ ชีวมวล — นอกเหนือจากนี้ส่วนใหญ่เป็นเชื้อเพลิงฟอสซิล"},{"q":"สารกึ่งตัวนำ (Semiconductor) เช่น ซิลิคอน มีความสำคัญต่ออุตสาหกรรมใดมากที่สุด","choices":["การผลิตชิปและอุปกรณ์อิเล็กทรอนิกส์","การผลิตอาหารแปรรูป","การก่อสร้างถนน","การทอผ้าและสิ่งทอ"],"correct":0,"hint":"นึกถึงคำว่า 'ชิปคอมพิวเตอร์' หรือ 'เซมิคอนดักเตอร์' มักปรากฏในข่าวอุตสาหกรรมประเภทใด","steps":["สารกึ่งตัวนำมีสมบัติควบคุมการนำไฟฟ้าได้ ทำให้สร้างเป็นทรานซิสเตอร์และวงจรรวมได้","ทรานซิสเตอร์คือหน่วยพื้นฐานของชิปคอมพิวเตอร์และอุปกรณ์อิเล็กทรอนิกส์ทุกชนิด","จึงเป็นวัสดุหัวใจสำคัญของอุตสาหกรรมอิเล็กทรอนิกส์และชิป"],"tip":"อุตสาหกรรมเซมิคอนดักเตอร์เป็นหนึ่งในอุตสาหกรรมยุทธศาสตร์ที่เกี่ยวข้องโดยตรงกับสายวิศวกรรมไฟฟ้า/คอมพิวเตอร์ที่คุณสนใจ"},{"q":"ข้อใดคือประโยชน์หลักของระบบ Cloud Computing","choices":["เข้าถึงและประมวลผลข้อมูลผ่านอินเทอร์เน็ตได้โดยไม่ต้องมีเครื่องแม่ข่ายของตัวเอง","ทำงานได้เฉพาะแบบออฟไลน์เท่านั้น","ต้องซื้อฮาร์ดแวร์ขนาดใหญ่มาเก็บไว้เองเสมอ","ใช้งานได้กับคอมพิวเตอร์เครื่องเดียวเท่านั้น"],"correct":0,"hint":"คำว่า 'Cloud' สื่อถึงการเก็บ/ประมวลผลข้อมูล 'อยู่ที่ไหนสักแห่งบนอินเทอร์เน็ต' ไม่ใช่ในเครื่องของเราเอง","steps":["Cloud Computing คือการใช้บริการเก็บข้อมูลและประมวลผลผ่านเซิร์ฟเวอร์ที่อยู่บนอินเทอร์เน็ต","ผู้ใช้ไม่จำเป็นต้องลงทุนซื้อและดูแลเครื่องแม่ข่าย (server) ของตัวเอง","สามารถเข้าถึงข้อมูลและทรัพยากรได้จากอุปกรณ์ใดก็ได้ที่เชื่อมต่ออินเทอร์เน็ต"],"tip":"บริการอย่าง Google Drive, iCloud หรือระบบที่บริษัทเทคโนโลยีใหญ่ๆ ใช้ ล้วนเป็นตัวอย่างของ Cloud Computing ในชีวิตประจำวัน"}]},
  {"id":"q_tpat3_news2","subjectId":"tpat3","title":"TPAT3 · ความสนใจข่าวสาร: เหตุการณ์สำคัญทางวิทยาศาสตร์","topic":"Science & Tech Literacy (Historical Milestones)","difficulty":"ง่าย","intro":{"concept":"ข้อสอบจริงบางข้อถามเหตุการณ์ข่าววิทยาศาสตร์เฉพาะช่วงเวลา (เช่น อุบัติเหตุนิวเคลียร์ที่เพิ่งเกิด) ซึ่งเปลี่ยนไปทุกปีและเว็บนี้ตามให้ทันไม่ได้ จึงเลือกใช้เหตุการณ์ประวัติศาสตร์วิทยาศาสตร์ที่มีชื่อเสียงและไม่เปลี่ยนแปลงแทน เพื่อฝึกทักษะความรู้รอบตัวแบบเดียวกันโดยไม่ล้าสมัย","worked":{"q":"ภารกิจอะพอลโล 11 (Apollo 11) เป็นที่จดจำในประวัติศาสตร์วิทยาศาสตร์เพราะเหตุการณ์ใด","steps":["อะพอลโล 11 เป็นภารกิจอวกาศของ NASA ในปี ค.ศ. 1969","นักบินอวกาศนีล อาร์มสตรองเป็นมนุษย์คนแรกที่เหยียบพื้นผิวดวงจันทร์","เหตุการณ์นี้ถือเป็นก้าวสำคัญของการสำรวจอวกาศของมนุษยชาติ"],"answer":"มนุษย์เหยียบดวงจันทร์เป็นครั้งแรก"}},"questions":[{"q":"การค้นพบเพนิซิลลิน (Penicillin) โดยอเล็กซานเดอร์ เฟลมมิง มีความสำคัญอย่างไรต่อวงการแพทย์","choices":["เป็นยาปฏิชีวนะชนิดแรกที่ใช้รักษาการติดเชื้อแบคทีเรีย","เป็นวัคซีนป้องกันไวรัสชนิดแรกของโลก","เป็นยาแก้ปวดที่ใช้กันแพร่หลายที่สุด","เป็นสารเคมีที่ใช้ฆ่าเชื้อบนพื้นผิวเท่านั้น"],"correct":0,"hint":"เพนิซิลลินเป็นจุดเริ่มต้นของยากลุ่มหนึ่งที่เปลี่ยนวงการแพทย์ในการรักษาโรคติดเชื้อ","steps":["อเล็กซานเดอร์ เฟลมมิง ค้นพบเพนิซิลลินโดยบังเอิญจากเชื้อราที่ปนเปื้อนในจานเพาะเชื้อแบคทีเรีย พ.ศ. 2471","เพนิซิลลินสามารถฆ่าเชื้อแบคทีเรียได้ จึงกลายเป็นยาปฏิชีวนะ (antibiotic) ชนิดแรกที่ใช้รักษาการติดเชื้อ","การค้นพบนี้ช่วยชีวิตผู้ป่วยติดเชื้อแบคทีเรียได้นับล้านคนตั้งแต่นั้นมา"],"tip":"เพนิซิลลินเป็นจุดเริ่มต้นของ 'ยุคยาปฏิชีวนะ' (antibiotic era) ที่เปลี่ยนแปลงการรักษาโรคติดเชื้อไปตลอดกาล เป็นหนึ่งในการค้นพบทางการแพทย์ที่สำคัญที่สุดในประวัติศาสตร์"},{"q":"โครงการจีโนมมนุษย์ (Human Genome Project) มีเป้าหมายหลักคืออะไร","choices":["ถอดรหัสลำดับดีเอ็นเอทั้งหมดของมนุษย์","สร้างมนุษย์โคลนนิ่งตัวแรกของโลก","พัฒนาวัคซีนป้องกันโรคมะเร็ง","ค้นหาสิ่งมีชีวิตนอกโลก"],"correct":0,"hint":"ชื่อโครงการมีคำว่า 'จีโนม' ซึ่งหมายถึงข้อมูลทางพันธุกรรมทั้งหมดของสิ่งมีชีวิต","steps":["จีโนม (genome) คือชุดข้อมูลพันธุกรรม (DNA) ทั้งหมดของสิ่งมีชีวิตชนิดหนึ่ง","โครงการจีโนมมนุษย์เป็นความร่วมมือระดับนานาชาติเพื่อถอดรหัสลำดับเบส DNA ทั้งหมดของมนุษย์","โครงการนี้เสร็จสมบูรณ์ในปี ค.ศ. 2003 และเป็นรากฐานสำคัญของการแพทย์แม่นยำ (precision medicine) ในปัจจุบัน"],"tip":"ข้อมูลจากโครงการจีโนมมนุษย์เป็นพื้นฐานของเทคโนโลยีการแพทย์สมัยใหม่หลายอย่าง เช่น การตรวจหาความเสี่ยงโรคทางพันธุกรรมและการพัฒนายาเฉพาะบุคคล"},{"q":"ทฤษฎีสัมพัทธภาพทั่วไป (General Relativity) ของอัลเบิร์ต ไอน์สไตน์ อธิบายแรงโน้มถ่วงด้วยแนวคิดหลักใด","choices":["แรงโน้มถ่วงคือผลจากการโค้งงอของกาล-อวกาศ (spacetime) จากมวล","แรงโน้มถ่วงคือแรงแม่เหล็กไฟฟ้าชนิดหนึ่ง","แรงโน้มถ่วงไม่มีอยู่จริง เป็นเพียงภาพลวงตา","แรงโน้มถ่วงเกิดจากอนุภาคขนาดเล็กที่มองไม่เห็น"],"correct":0,"hint":"ทฤษฎีนี้เปลี่ยนมุมมองเรื่องแรงโน้มถ่วงจาก 'แรงดึงดูด' แบบนิวตัน ไปเป็นเรื่อง 'รูปทรงของปริภูมิ' แทน","steps":["ก่อนหน้านี้ นิวตันอธิบายแรงโน้มถ่วงว่าเป็นแรงดึงดูดระหว่างมวลสองก้อน","ไอน์สไตน์เสนอมุมมองใหม่ว่ามวลทำให้กาล-อวกาศ (spacetime) โค้งงอ และวัตถุอื่นเคลื่อนที่ตามความโค้งนั้น","สิ่งที่เรารู้สึกว่าเป็น 'แรงโน้มถ่วง' จึงเป็นผลจากการเคลื่อนที่ตามความโค้งของกาล-อวกาศ ไม่ใช่แรงดึงดูดโดยตรง"],"tip":"การทดลองยืนยันทฤษฎีนี้ที่มีชื่อเสียงคือการสังเกตแสงดาวโค้งงอเมื่อผ่านใกล้ดวงอาทิตย์ระหว่างเกิดสุริยุปราคาปี ค.ศ. 1919 ซึ่งทำให้ไอน์สไตน์โด่งดังไปทั่วโลก"},{"q":"อเล็กซานเดอร์ เกรแฮม เบลล์ เป็นที่รู้จักจากการประดิษฐ์อุปกรณ์ใดที่เปลี่ยนแปลงการสื่อสารของมนุษย์","choices":["โทรศัพท์","วิทยุ","โทรทัศน์","คอมพิวเตอร์"],"correct":0,"hint":"อุปกรณ์นี้ทำให้มนุษย์คุยกันด้วยเสียงได้ทันทีแม้อยู่ไกลกันผ่านสายไฟฟ้า","steps":["อเล็กซานเดอร์ เกรแฮม เบลล์ จดสิทธิบัตรโทรศัพท์เครื่องแรกในปี ค.ศ. 1876","อุปกรณ์นี้เปลี่ยนสัญญาณเสียงเป็นสัญญาณไฟฟ้าแล้วส่งผ่านสายไปยังอีกเครื่องหนึ่ง","การประดิษฐ์นี้ปฏิวัติการสื่อสารทางไกลของมนุษย์และเป็นรากฐานของระบบโทรคมนาคมสมัยใหม่"],"tip":"หลักการแปลงเสียงเป็นสัญญาณไฟฟ้าแล้วส่งผ่านสายของโทรศัพท์ยุคแรก เป็นจุดเริ่มต้นแนวคิดที่พัฒนาต่อมาเป็นระบบโทรคมนาคมและอินเทอร์เน็ตในปัจจุบัน"}]},
  {"id":"q_tpat3_pattern2","subjectId":"tpat3","title":"TPAT3 · ด้านตัวเลข ชุดที่ 3","topic":"Numerical Reasoning (Number Patterns & Custom Operations)","difficulty":"ยาก","intro":{"concept":"ชุดนี้เพิ่มรูปแบบลำดับที่ซับซ้อนขึ้น (ผลต่างไม่คงที่, อัตราส่วนคงที่) และโจทย์นิยามการดำเนินการเองอีกแบบ พร้อมโจทย์อัตราส่วนแบ่งเงิน — เทคนิคเดิมยังใช้ได้: หาผลต่าง/อัตราส่วนระหว่างพจน์ก่อนเสมอ และตรวจสอบสูตรกับตัวอย่างที่ให้มาก่อนนำไปใช้กับค่าใหม่","worked":{"q":"ลำดับ 100, 90, 81, 73, ? พจน์ถัดไปคือเท่าใด","steps":["หาผลต่างระหว่างพจน์: 90−100=−10, 81−90=−9, 73−81=−8","ผลต่างเพิ่มขึ้นทีละ 1 (−10,−9,−8,...) ผลต่างถัดไปคือ −7","พจน์ถัดไป = 73+(−7) = 66"],"answer":"66"}},"questions":[{"q":"ลำดับ 3, 9, 27, 81, ? พจน์ถัดไปคือเท่าใด","choices":["162","203","243","270"],"correct":2,"hint":"ลองหาอัตราส่วนระหว่างพจน์ที่ติดกันแทนการหาผลต่าง","steps":["เทียบพจน์ที่ติดกัน: 9÷3=3, 27÷9=3, 81÷27=3","แต่ละพจน์เป็น 3 เท่าของพจน์ก่อนหน้าเสมอ (อัตราส่วนคงที่)","พจน์ถัดไป = 81×3 = 243"],"tip":"ถ้าลบกันแล้วไม่เห็นรูปแบบชัดเจน ให้ลองหารกันดูแทน อาจเป็นลำดับที่มีอัตราส่วนคงที่แทนผลต่างคงที่"},{"q":"กำหนดการดำเนินการ a※b = a×b − b เมื่อ 2※3 = 3 และ 4※2 = 6 จงหาค่าของ 5※2","choices":["6","7","8","9"],"correct":2,"hint":"ตรวจสอบสูตร a×b−b กับตัวอย่างทั้งสองก่อน แล้วแทนค่าใหม่","steps":["ตรวจสอบกับตัวอย่างแรก: 2※3 = 2×3−3 = 6−3 = 3 ✓","ตรวจสอบกับตัวอย่างที่สอง: 4※2 = 4×2−2 = 8−2 = 6 ✓","สูตรถูกต้อง แทนค่า 5※2 = 5×2−2 = 10−2","ผลลัพธ์ = 8"],"tip":"เมื่อตรวจสอบสูตรกับตัวอย่างที่ให้มาแล้วตรงทั้งคู่ ให้มั่นใจใช้สูตรนั้นแทนค่าใหม่ได้เลย ไม่ต้องหาสูตรอื่นเพิ่ม"},{"q":"ลำดับ 100, 90, 81, 73, ? พจน์ถัดไปคือเท่าใด","choices":["64","65","66","68"],"correct":2,"hint":"หาผลต่างระหว่างพจน์ที่ติดกันก่อน แล้วดูว่าผลต่างนั้นเปลี่ยนแปลงอย่างมีระบบหรือไม่","steps":["หาผลต่าง: 90−100=−10, 81−90=−9, 73−81=−8","ผลต่างเพิ่มขึ้นทีละ 1 (ลดการลดลง): −10,−9,−8,...","ผลต่างถัดไปคือ −7","พจน์ถัดไป = 73−7 = 66"],"tip":"ลำดับที่ลดลงเรื่อยๆ แต่ลดลงน้อยลงทุกครั้ง (ผลต่างติดลบที่เพิ่มขึ้น) เป็นรูปแบบที่พบได้บ่อยพอๆ กับลำดับที่เพิ่มขึ้น อย่าตกใจกับเครื่องหมายลบ"},{"q":"แบ่งเงิน 3,000 บาท ตามอัตราส่วน 2:3:5 ให้คน 3 คน คนที่ได้เงินมากที่สุดจะได้เงินเท่าใด","choices":["600 บาท","900 บาท","1,200 บาท","1,500 บาท"],"correct":3,"hint":"รวมส่วนทั้งหมดก่อน แล้วหาว่า 1 ส่วนเท่ากับกี่บาท","steps":["รวมส่วนทั้งหมด: 2+3+5 = 10 ส่วน","1 ส่วน = 3,000÷10 = 300 บาท","คนที่ได้มากที่สุด (5 ส่วน) = 5×300 = 1,500 บาท"],"tip":"โจทย์แบ่งตามอัตราส่วน 3 ฝ่ายขึ้นไป ให้รวมส่วนทั้งหมดก่อนเสมอ แล้วหาค่าต่อ 1 ส่วน ก่อนคูณหาแต่ละฝ่าย"}]},
  {"id":"q_tpat3_mech3","subjectId":"tpat3","title":"TPAT3 · ด้านกลศาสตร์ ชุดที่ 3","topic":"Mechanical Reasoning (โมเมนต์ ความดัน จุดศูนย์ถ่วง)","difficulty":"ยาก","intro":{"concept":"ชุดนี้ผสมโจทย์คำนวณโมเมนต์กับโจทย์มโนทัศน์เรื่องความดัน (P=F/A) และเสถียรภาพของวัตถุ (จุดศูนย์ถ่วง) — หลักการเดิมยังใช้ได้: โมเมนต์ต้องเท่ากันสองข้างเมื่อสมดุล ส่วนความดันแปรผกผันกับพื้นที่ที่รับแรง","worked":{"q":"คานเบามีจุดหมุน ด้านซ้ายมีแรง 40N ห่างจุดหมุน 3m ด้านขวาห่างจุดหมุน 4m ต้องใช้แรงเท่าใดจึงสมดุลพอดี","steps":["ใช้หลักโมเมนต์: แรง×ระยะ ต้องเท่ากันสองฝั่ง","แทนค่า 40×3 = F×4","จัดสมการ F = 120/4 = 30N"],"answer":"30N"}},"questions":[{"q":"คานเบามีจุดหมุน ด้านซ้ายมีแรง 40N ห่างจุดหมุน 3m ด้านขวาห่างจุดหมุน 4m ต้องใช้แรงเท่าใดจึงสมดุลพอดี","choices":["20N","25N","30N","35N"],"correct":2,"hint":"ใช้หลักโมเมนต์: แรง×ระยะ ต้องเท่ากันทั้งสองฝั่งของจุดหมุนเมื่อสมดุล","steps":["หลักโมเมนต์: แรงซ้าย×ระยะซ้าย = แรงขวา×ระยะขวา","แทนค่า 40×3 = F×4","จัดสมการ F = 120/4 = 30N"],"tip":"หลักโมเมนต์คือหัวใจของโจทย์สมดุลทุกข้อ จำสูตร 'แรง×ระยะ' ต้องเท่ากันสองข้างของจุดหมุนเสมอ"},{"q":"เหตุใดปลายเข็มที่แหลมจึงเจาะทะลุวัสดุได้ง่ายกว่าการใช้ปลายนิ้วกด ทั้งที่ออกแรงเท่ากัน","choices":["เข็มมีแรงมากกว่านิ้ว","พื้นที่หน้าตัดของเข็มเล็กกว่ามาก ทำให้เกิดความดันสูงกว่า","เข็มมีน้ำหนักเบากว่านิ้ว","ไม่มีความแตกต่างที่แท้จริงระหว่างสองวิธี"],"correct":1,"hint":"ความดันคำนวณจาก P=F/A เมื่อแรงเท่ากัน ตัวแปรที่ต่างกันคือพื้นที่หน้าตัด","steps":["ความดัน P = แรง/พื้นที่ (P=F/A) เมื่อแรงเท่ากัน ความดันจะแปรผกผันกับพื้นที่","ปลายเข็มมีพื้นที่หน้าตัดเล็กมากเมื่อเทียบกับปลายนิ้ว","พื้นที่ที่เล็กกว่ามากทำให้เกิดความดันสูงกว่ามาก จึงเจาะทะลุวัสดุได้ง่ายกว่า"],"tip":"หลักการนี้อธิบายได้ทั้งเข็มเจาะ ใบมีดคม และรองเท้าส้นสูงที่กดพื้นเป็นรอย — พื้นที่สัมผัสยิ่งเล็ก ความดัน ณ จุดนั้นยิ่งสูงเมื่อแรงเท่ากัน"},{"q":"ระบบรอกผสม (รอกตายตัว 1 ตัว ต่อกับรอกเคลื่อนที่ 1 ตัว) ในอุดมคติ ช่วยผ่อนแรงได้กี่เท่าเมื่อเทียบกับการยกน้ำหนักโดยตรง","choices":["1 เท่า","2 เท่า","3 เท่า","4 เท่า"],"correct":1,"hint":"รอกตายตัวช่วยแค่เปลี่ยนทิศทาง ไม่ช่วยผ่อนแรง ส่วนรอกเคลื่อนที่ช่วยผ่อนแรงได้ 2 เท่า ลองรวมผลทั้งสองเข้าด้วยกัน","steps":["รอกตายตัว (fixed pulley) เปลี่ยนแค่ทิศทางแรง ไม่เพิ่มการผ่อนแรงเลย (mechanical advantage = 1)","รอกเคลื่อนที่ (movable pulley) ผ่อนแรงได้ 2 เท่า เพราะมีเชือก 2 เส้นรับน้ำหนัก","เมื่อต่อรวมกัน mechanical advantage รวม = 1×2 = 2 เท่า"],"tip":"การต่อรอกตายตัวเพิ่มเข้าไปมักมีจุดประสงค์แค่เปลี่ยนทิศทางการดึงให้สะดวก (เช่น ดึงลงแทนดึงขึ้น) ไม่ได้เพิ่มการผ่อนแรงเลย ต้องนับเฉพาะรอกเคลื่อนที่ในการคำนวณ mechanical advantage"},{"q":"วัตถุจะมีเสถียรภาพน้อยลง (ล้มคว่ำง่ายขึ้น) เมื่อจุดศูนย์ถ่วงอยู่ในลักษณะใด","choices":["อยู่ต่ำและฐานกว้าง","อยู่สูงและฐานแคบ","อยู่กึ่งกลางพอดีระหว่างฐานทั้งสองด้าน","ไม่เกี่ยวข้องกับตำแหน่งจุดศูนย์ถ่วงเลย"],"correct":1,"hint":"ลองนึกถึงรถแข่งตัวเตี้ยฐานกว้างเทียบกับตึกสูงฐานแคบ อันไหนล้มง่ายกว่าเมื่อถูกแรงกระแทกด้านข้าง","steps":["เสถียรภาพของวัตถุขึ้นกับความสูงของจุดศูนย์ถ่วงและความกว้างของฐานที่รองรับ","จุดศูนย์ถ่วงยิ่งสูงและฐานยิ่งแคบ วัตถุยิ่งเอียงล้มได้ง่ายเมื่อถูกแรงกระทำเพียงเล็กน้อย","วัตถุที่มีจุดศูนย์ถ่วงต่ำและฐานกว้าง (เช่น รถแข่ง) จะมีเสถียรภาพสูงกว่ามาก"],"tip":"หลักการนี้เป็นเหตุผลที่รถแข่งออกแบบให้เตี้ยและฐานล้อกว้าง ขณะที่ของเล่นล้มลุก (ตุ๊กตาไม่ล้ม) ออกแบบให้จุดศูนย์ถ่วงอยู่ต่ำสุดที่ฐานกลม"}]},
  {"id":"q_tpat3_sci3","subjectId":"tpat3","title":"TPAT3 · ความคิดเชิงวิทยาศาสตร์ ชุดที่ 3","topic":"Scientific Thinking (ตัวแปรในการทดลอง)","difficulty":"ยาก","intro":{"concept":"การทดลองทางวิทยาศาสตร์แบ่งตัวแปรเป็น 3 ประเภท: ตัวแปรต้น (สิ่งที่ตั้งใจเปลี่ยนแปลง) ตัวแปรตาม (ผลลัพธ์ที่วัดได้) และตัวแปรควบคุม (สิ่งที่ต้องคงที่ทุกกรณี) — การระบุตัวแปรแต่ละประเภทให้ถูกต้องเป็นทักษะพื้นฐานที่สุดของการออกแบบการทดลอง","worked":{"q":"ในการทดลองเปรียบเทียบการเจริญเติบโตของพืชที่ได้รับปุ๋ยต่างชนิดกัน (เงื่อนไขอื่นเหมือนกันหมด) 'ชนิดของปุ๋ย' เป็นตัวแปรประเภทใด","steps":["ตัวแปรต้นคือสิ่งที่ผู้ทดลองตั้งใจเปลี่ยนแปลงเพื่อดูผล","ในที่นี้ผู้ทดลองตั้งใจเปลี่ยน 'ชนิดของปุ๋ย' เพื่อดูผลต่อการเจริญเติบโต","ดังนั้น 'ชนิดของปุ๋ย' เป็นตัวแปรต้น"],"answer":"ตัวแปรต้น"}},"questions":[{"q":"ทดลองปลูกพืชสองกระถาง กระถางหนึ่งรดน้ำทุกวัน อีกกระถางรดน้ำสัปดาห์ละครั้ง เงื่อนไขอื่น (แสง ดิน อุณหภูมิ) เหมือนกันหมด 'ความถี่ในการรดน้ำ' เป็นตัวแปรประเภทใด","choices":["ตัวแปรต้น","ตัวแปรตาม","ตัวแปรควบคุม","ไม่ใช่ตัวแปรของการทดลองนี้"],"correct":0,"hint":"ตัวแปรต้นคือสิ่งที่ผู้ทดลองจงใจเปลี่ยนแปลงระหว่างสองกลุ่มเพื่อเปรียบเทียบผล","steps":["ผู้ทดลองจงใจเปลี่ยน 'ความถี่ในการรดน้ำ' ระหว่างสองกระถาง (ทุกวัน vs สัปดาห์ละครั้ง)","สิ่งที่จงใจเปลี่ยนแปลงเพื่อดูผลกระทบ คือตัวแปรต้น (independent variable)","ดังนั้น 'ความถี่ในการรดน้ำ' เป็นตัวแปรต้น"],"tip":"ตัวแปรต้นมักเป็นสิ่งที่ปรากฏในคำถามวิจัย เช่น 'ผลของ [ตัวแปรต้น] ต่อ [ตัวแปรตาม]' — ในที่นี้คือ 'ผลของความถี่การรดน้ำต่อการเจริญเติบโต'"},{"q":"การทดลองเดียวกับข้อก่อนหน้า 'การเจริญเติบโตของพืช' (เช่น ความสูง จำนวนใบ) เป็นตัวแปรประเภทใด","choices":["ตัวแปรต้น","ตัวแปรตาม","ตัวแปรควบคุม","ไม่ใช่ตัวแปรของการทดลองนี้"],"correct":1,"hint":"ตัวแปรตามคือผลลัพธ์ที่วัดได้หลังจากเปลี่ยนตัวแปรต้นแล้ว","steps":["ตัวแปรตาม (dependent variable) คือสิ่งที่ผู้ทดลองวัดผลเพื่อดูว่าได้รับผลกระทบจากตัวแปรต้นหรือไม่","ในที่นี้ผู้ทดลองวัด 'การเจริญเติบโตของพืช' เพื่อดูผลจากความถี่การรดน้ำ","ดังนั้น 'การเจริญเติบโตของพืช' เป็นตัวแปรตาม"],"tip":"ตัวแปรตามคือสิ่งที่ 'ขึ้นอยู่กับ' ตัวแปรต้นเสมอ (dependent = ขึ้นอยู่กับ) เป็นสิ่งที่นักวิจัยเก็บข้อมูล/วัดผลจริงในการทดลอง"},{"q":"วิศวกรออกแบบผลิตภัณฑ์ต้นแบบเสร็จแล้ว นำไปให้กลุ่มผู้ใช้จริงทดลองใช้งานก่อนผลิตจำนวนมาก ขั้นตอนนี้เรียกว่าอะไร","choices":["การผลิตจำนวนมาก (mass production)","การทดสอบกับผู้ใช้จริง (user testing)","การจดสิทธิบัตร (patent filing)","การโฆษณาสินค้า (advertising)"],"correct":1,"hint":"ขั้นตอนนี้เป็นส่วนหนึ่งของกระบวนการออกแบบเชิงวิศวกรรมที่เกิดขึ้นหลังสร้างต้นแบบ ก่อนผลิตจริง","steps":["หลังสร้างต้นแบบ (prototype) แล้ว ขั้นตอนถัดไปคือการทดสอบว่าใช้งานได้ดีจริงหรือไม่","การให้ผู้ใช้จริงทดลองใช้เรียกว่า user testing เป็นส่วนหนึ่งของขั้นตอน 'ทดสอบ' ในกระบวนการออกแบบเชิงวิศวกรรม","ขั้นตอนนี้ช่วยพบปัญหาที่วิศวกรอาจมองข้ามก่อนลงทุนผลิตจำนวนมาก"],"tip":"user testing ช่วยพบ 'ปัญหาที่ผู้ใช้จริงเจอ' ซึ่งต่างจากมุมมองของวิศวกรผู้ออกแบบ เป็นขั้นตอนสำคัญที่บริษัทเทคโนโลยีใหญ่ๆ ทำก่อนเปิดตัวผลิตภัณฑ์เสมอ"},{"q":"ถ้าเพิ่มแรงเสียดทานระหว่างล้อรถกับพื้นถนน (เช่น เปลี่ยนยางใหม่ที่มีดอกยางดีกว่า) รถจะใช้ระยะทางในการเบรกจนหยุดสั้นลงหรือยาวขึ้น","choices":["สั้นลง","ยาวขึ้น","ไม่เปลี่ยนแปลง","ขึ้นอยู่กับสีของตัวรถ"],"correct":0,"hint":"แรงเสียดทานเป็นแรงที่ต้านการเคลื่อนที่ ลองคิดว่าแรงต้านที่มากขึ้นจะทำให้รถหยุดเร็วขึ้นหรือช้าลง","steps":["แรงเสียดทานเป็นแรงที่ต้านทานการเคลื่อนที่ระหว่างผิวสัมผัสสองผิว","เมื่อแรงเสียดทานระหว่างล้อกับถนนมากขึ้น แรงต้านการไถลก็มากขึ้นตามไปด้วย","แรงต้านที่มากขึ้นทำให้รถชะลอความเร็วได้เร็วขึ้น จึงใช้ระยะทางเบรกสั้นลง"],"tip":"หลักการนี้คือเหตุผลที่ยางรถต้องเปลี่ยนเมื่อดอกยางสึก (ดอกยางสึก = แรงเสียดทานลดลง = ระยะเบรกยาวขึ้น = อันตรายมากขึ้น) โดยเฉพาะบนถนนเปียก"}]},
  {"id":"q_tpat3_mech4","subjectId":"tpat3","title":"TPAT3 · ด้านกลศาสตร์และฟิสิกส์: วงจรไฟฟ้าเชิงคำนวณ","topic":"Mechanical & Physics Aptitude (Circuits & Matter)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดความรู้เชิงมโนทัศน์เรื่องวงจรไฟฟ้า มาเป็นโจทย์คำนวณจริงด้วยกฎของโอห์มและความต้านทานรวม — พื้นฐานเหล่านี้เป็นจุดเริ่มต้นของการวิเคราะห์วงจรไฟฟ้าทุกชนิดในวิศวกรรมไฟฟ้า","worked":{"q":"วงจรไฟฟ้ามีความต่างศักย์ 12V ต่อกับตัวต้านทาน 4Ω กระแสไฟฟ้าที่ไหลผ่านมีค่าเท่าใด","steps":["ใช้กฎของโอห์ม: V = IR หรือจัดรูปเป็น I = V/R","แทนค่า I = 12/4","คำนวณ I = 3A"],"answer":"3A"}},"questions":[{"q":"วงจรไฟฟ้ามีความต่างศักย์ 12V ต่อกับตัวต้านทาน 4Ω กระแสไฟฟ้าที่ไหลผ่านมีค่าเท่าใด","choices":["3A","48A","8A","0.33A"],"correct":0,"hint":"ใช้กฎของโอห์ม I = V/R","steps":["กฎของโอห์ม: I = V/R","แทนค่า I = 12/4","คำนวณ I = 3A"],"tip":"กฎของโอห์ม V=IR เป็นสูตรพื้นฐานที่สุดของวงจรไฟฟ้า จำได้แม่นแล้วจัดรูปสมการหาตัวแปรที่ต้องการได้เสมอ"},{"q":"ต่อตัวต้านทาน 3 ตัวแบบอนุกรม ค่า 2Ω, 3Ω และ 5Ω ตามลำดับ ความต้านทานรวมของวงจรมีค่าเท่าใด","choices":["10Ω","30Ω","0.97Ω","5Ω"],"correct":0,"hint":"ความต้านทานรวมแบบอนุกรมคือผลบวกของทุกตัวตรงๆ","steps":["สูตรความต้านทานรวมแบบอนุกรม: R รวม = R1+R2+R3","แทนค่า R รวม = 2+3+5","คำนวณ R รวม = 10Ω"],"tip":"วงจรอนุกรมบวกความต้านทานตรงๆ ได้เลย ยิ่งต่อเพิ่มยิ่งต้านทานมากขึ้น ต่างจากวงจรขนานที่ต้องใช้สูตรผลรวมส่วนกลับ"},{"q":"ต่อตัวต้านทาน 2 ตัวแบบขนาน ค่า 6Ω และ 3Ω ความต้านทานรวมของวงจรมีค่าเท่าใด","choices":["2Ω","9Ω","4.5Ω","18Ω"],"correct":0,"hint":"ความต้านทานรวมแบบขนานใช้สูตรผลรวมส่วนกลับ 1/R รวม = 1/R1+1/R2","steps":["สูตรความต้านทานรวมแบบขนาน: 1/R รวม = 1/R1+1/R2","แทนค่า 1/R รวม = 1/6+1/3 = 1/6+2/6 = 3/6 = 1/2","จัดสมการ R รวม = 2Ω"],"tip":"ความต้านทานรวมแบบขนานจะน้อยกว่าตัวต้านทานที่น้อยที่สุดในกลุ่มเสมอ (ในที่นี้น้อยกว่า 3Ω) — ใช้ตรวจคำตอบคร่าวๆ ได้ว่าคำนวณถูกทิศทางหรือไม่"},{"q":"วัตถุชิ้นหนึ่งมีความหนาแน่น 2.7 g/cm³ และมีปริมาตร 20 cm³ วัตถุนี้มีมวลเท่าใด","choices":["54g","7.4g","22.7g","2.7g"],"correct":0,"hint":"ใช้สูตรความหนาแน่น: ความหนาแน่น = มวล/ปริมาตร จัดรูปหามวล","steps":["สูตรความหนาแน่น: ρ = m/V จัดรูปเป็น m = ρ×V","แทนค่า m = 2.7×20","คำนวณ m = 54g"],"tip":"สูตร ρ=m/V เป็นสูตรพื้นฐานของสมบัติสสารที่ใช้บ่อยพอๆ กับกฎของโอห์มในวงจรไฟฟ้า จำการจัดรูปสมการหาตัวแปรต่างๆ ให้คล่อง"}]},
  {"id":"q_tpat3_mech5","subjectId":"tpat3","title":"TPAT3 · ด้านกลศาสตร์: เครื่องกลอย่างง่าย ชุดที่ 2","topic":"Mechanical Reasoning (Simple Machines)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (รอก เฟือง คานงัด ล้อและเพลา) มาเป็นพื้นเอียง สกรู คานงัดชนิดที่ 3 และการแลกเปลี่ยนระหว่างแรงบิดกับความเร็วในระบบเฟือง — หลักการแลกเปลี่ยน 'แรง vs ระยะทาง/ความเร็ว' นี้เป็นแนวคิดเดียวกับการแลกเปลี่ยน 'แรงดัน vs กระแส' ในหม้อแปลงไฟฟ้า ซึ่งเป็นพื้นฐานสำคัญของวิศวกรรมไฟฟ้า","worked":{"q":"พื้นเอียงยาว 5m สูง 1m ใช้ยกวัตถุขึ้นแทนการยกตรงๆ ในอุดมคติ (ไม่มีแรงเสียดทาน) พื้นเอียงนี้ช่วยผ่อนแรงได้กี่เท่า","steps":["สูตร mechanical advantage ของพื้นเอียง = ความยาวพื้นเอียง/ความสูงที่ยกขึ้น","แทนค่า MA = 5/1","คำนวณ MA = 5 เท่า"],"answer":"5 เท่า"}},"questions":[{"q":"พื้นเอียงยาว 5m สูง 1m ใช้ยกวัตถุขึ้นแทนการยกตรงๆ ในอุดมคติ (ไม่มีแรงเสียดทาน) พื้นเอียงนี้ช่วยผ่อนแรงได้กี่เท่า","choices":["5 เท่า","1 เท่า","0.2 เท่า","6 เท่า"],"correct":0,"hint":"mechanical advantage ของพื้นเอียง = ความยาวพื้นเอียง/ความสูงที่ยกขึ้น","steps":["สูตร MA พื้นเอียง = ความยาว/ความสูง","แทนค่า MA = 5/1","คำนวณ MA = 5 เท่า"],"tip":"พื้นเอียงยิ่งยาวเทียบกับความสูงเท่าใด ยิ่งผ่อนแรงได้มากเท่านั้น (แต่ต้องออกแรงในระยะทางที่ไกลขึ้นเป็นการแลกเปลี่ยน) ทางลาดสำหรับรถเข็นจึงมักทำให้ยาวเพื่อผ่อนแรง"},{"q":"คันโยกชนิดที่ 3 (แรงพยายามอยู่ระหว่างจุดหมุนกับแรงต้าน เช่น ตะเกียบ แขนคนยกของ) มีคุณสมบัติเชิงกลอย่างไร","choices":["mechanical advantage มากกว่า 1 เสมอ ได้เปรียบแรง","mechanical advantage น้อยกว่า 1 เสียเปรียบแรงแต่ได้เปรียบระยะทาง/ความเร็วในการเคลื่อนที่","mechanical advantage เท่ากับ 1 เสมอ ไม่ได้เปรียบหรือเสียเปรียบเลย","ไม่สามารถระบุได้ ขึ้นอยู่กับวัสดุที่ใช้ทำคาน"],"correct":1,"hint":"เปรียบเทียบระยะจากจุดหมุนถึงจุดออกแรงกับระยะจากจุดหมุนถึงแรงต้าน — จุดออกแรงอยู่ใกล้จุดหมุนกว่าเสมอในคันโยกชนิดที่ 3","steps":["คันโยกชนิดที่ 3 มีจุดออกแรงอยู่ระหว่างจุดหมุนกับแรงต้าน จึงมีระยะจากจุดหมุนถึงจุดออกแรงสั้นกว่าระยะจากจุดหมุนถึงแรงต้านเสมอ","ตามหลักโมเมนต์ ระยะออกแรงสั้นกว่าหมายถึงต้องออกแรงมากกว่าแรงต้าน (mechanical advantage < 1)","แต่แลกมาด้วยจุดปลาย (แรงต้าน) เคลื่อนที่ได้เร็วและไกลกว่าจุดออกแรงมาก เหมาะกับงานที่ต้องการความเร็ว/ระยะทางมากกว่าแรง เช่น การเคี้ยวอาหาร (กราม) หรือการเหวี่ยงแขน"],"tip":"คันโยกชนิดที่ 3 ต่างจากชนิดที่ 1 และ 2 ตรงที่ 'เสียเปรียบแรงเสมอ' แต่ร่างกายมนุษย์ใช้คันโยกชนิดนี้เยอะมาก (แขน ขา กราม) เพราะธรรมชาติต้องการความเร็วในการเคลื่อนไหวมากกว่าแรงดิบ"},{"q":"เฟืองขับ (A) มีฟัน 10 ซี่ ขบกับเฟืองตาม (B) ที่มีฟัน 30 ซี่ ข้อใดถูกต้องเกี่ยวกับการหมุนของเฟือง B เทียบกับเฟือง A","choices":["หมุนช้าลง 3 เท่า แต่แรงบิดมากขึ้น 3 เท่า","หมุนเร็วขึ้น 3 เท่า และแรงบิดมากขึ้น 3 เท่าด้วย","หมุนช้าลง 3 เท่า และแรงบิดลดลง 3 เท่าด้วย","หมุนเร็วเท่าเดิม แต่แรงบิดมากขึ้น 3 เท่า"],"correct":0,"hint":"อัตราทดเฟืองทำให้ความเร็วรอบกับแรงบิดแปรผกผันกันเสมอ — พลังงานที่ส่งผ่านคงที่ (ไม่นับการสูญเสีย)","steps":["อัตราทดเฟือง = จำนวนฟันเฟืองตาม/จำนวนฟันเฟืองขับ = 30/10 = 3","เฟืองที่มีฟันมากกว่าจะหมุนช้ากว่าเฟืองที่มีฟันน้อยกว่าตามอัตราส่วนนี้ ดังนั้นเฟือง B หมุนช้าลง 3 เท่า","แต่แรงบิด (torque) แปรผกผันกับความเร็วรอบเมื่อพลังงานที่ส่งผ่านคงที่ ดังนั้นเฟือง B มีแรงบิดมากขึ้น 3 เท่า"],"tip":"หลักการแลกเปลี่ยน 'ความเร็ว vs แรงบิด' นี้เหมือนกับหลักการแลกเปลี่ยน 'กระแส vs แรงดัน' ในหม้อแปลงไฟฟ้าทุกประการ (พลังงาน/กำลังคงที่ ตัวแปรหนึ่งเพิ่มอีกตัวต้องลด) เป็นแนวคิดที่ใช้ซ้ำได้ทั้งในกลศาสตร์และวิศวกรรมไฟฟ้า"},{"q":"สกรู (screw) โดยพื้นฐานแล้วเป็นการประยุกต์จากเครื่องกลอย่างง่ายชนิดใด","choices":["พื้นเอียงที่พันรอบแกนทรงกระบอก","คานงัดธรรมดา","รอกเดี่ยวตายตัว","ล้อและเพลา"],"correct":0,"hint":"ลองจินตนาการคลี่เกลียวสกรูออกมาเป็นเส้นตรง จะมีรูปร่างคล้ายเครื่องกลอย่างง่ายชนิดใด","steps":["ถ้าคลี่เกลียวของสกรูออกมาเป็นเส้นตรง จะได้รูปร่างเป็นพื้นเอียงยาวๆ เส้นหนึ่ง","สกรูคือการพันพื้นเอียงนั้นรอบแกนทรงกระบอก ทำให้ได้พื้นเอียงที่ยาวมากในพื้นที่กะทัดรัด","ยิ่งเกลียวถี่ (ระยะพิตช์สั้น) เท่ากับพื้นเอียงยิ่งยาว ยิ่งผ่อนแรงได้มาก แต่ต้องหมุนหลายรอบกว่าจะเคลื่อนที่ได้ระยะเท่าเดิม"],"tip":"หลักการนี้อธิบายได้ว่าทำไมสกรูตัวเล็กๆ ถึงยึดวัสดุแน่นหนามาก (mechanical advantage สูงมาก) เพราะเป็นพื้นเอียงที่ 'ซ่อน' ความยาวไว้ในรูปเกลียวรอบแกน"}]},
  {"id":"q_tpat3_word2","subjectId":"tpat3","title":"TPAT3 · ด้านตัวเลข: สัดส่วน เปอร์เซ็นต์ อัตราส่วนผกผัน ชุดที่ 2","topic":"Numerical Reasoning (สัดส่วน เปอร์เซ็นต์ อัตราส่วนผกผัน)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (อัตราส่วนต่อเนื่อง, งาน-คน-วัน, เปอร์เซ็นต์เพิ่ม/ลด) มาเป็นอัตราส่วนผกผันแบบความเร็ว-เวลา, เปอร์เซ็นต์ซ้อนกันหลายชั้น (successive percentage) และอัตราส่วนผสม — โจทย์แนวนี้พบบ่อยมากในข้อสอบจริงเพราะทดสอบว่าเข้าใจ 'อัตราส่วนตรง' กับ 'อัตราส่วนผกผัน' ต่างกันอย่างไร ไม่ใช่แค่คำนวณเป็น","worked":{"q":"รถวิ่งด้วยความเร็ว 60 km/h ใช้เวลา 3 ชั่วโมงถึงจุดหมาย ถ้าต้องการใช้เวลาแค่ 2 ชั่วโมง (ระยะทางเท่าเดิม) ต้องใช้ความเร็วเท่าใด","steps":["ระยะทางคงที่ ความเร็วกับเวลาจึงเป็นอัตราส่วนผกผันกัน: v1×t1 = v2×t2","แทนค่า 60×3 = v2×2 → 180 = v2×2","จัดสมการ v2 = 180/2 = 90 km/h"],"answer":"90 km/h"}},"questions":[{"q":"รถวิ่งด้วยความเร็ว 60 km/h ใช้เวลา 3 ชั่วโมงถึงจุดหมาย ถ้าต้องการใช้เวลาแค่ 2 ชั่วโมง (ระยะทางเท่าเดิม) ต้องใช้ความเร็วเท่าใด","choices":["90 km/h","40 km/h","120 km/h","30 km/h"],"correct":0,"hint":"ระยะทางคงที่ ความเร็วกับเวลาจึงแปรผกผันกัน ใช้ v1×t1 = v2×t2","steps":["ระยะทางคงที่: v1×t1 = v2×t2","แทนค่า 60×3 = v2×2 → 180 = 2v2","จัดสมการ v2 = 90 km/h"],"tip":"สัญญาณว่าเป็นอัตราส่วนผกผันคือมี 'ตัวหนึ่งคงที่เสมอ' (ระยะทาง) ให้ตัวแปรอีกสองตัวคูณกันแล้วเท่ากันทั้งสองสถานการณ์ ต่างจากอัตราส่วนตรงที่ผลหารเท่ากัน"},{"q":"สินค้าราคา 500 บาท ลดราคา 20% แล้วคิดภาษี 7% จากราคาที่ลดแล้ว ราคาสุดท้ายเป็นเท่าใด","choices":["428 บาท","365 บาท","435 บาท","400 บาท"],"correct":0,"hint":"เปอร์เซ็นต์ซ้อนกันหลายชั้นต้องคูณต่อเนื่องทีละขั้น ห้ามบวก/ลบเปอร์เซ็นต์ตรงๆ","steps":["ลด 20% ก่อน: 500×(1−0.20) = 500×0.8 = 400 บาท","คิดภาษี 7% จากราคาที่ลดแล้ว (ไม่ใช่ราคาเดิม): 400×(1+0.07) = 400×1.07","คำนวณ = 428 บาท"],"tip":"ข้อผิดพลาดที่พบบ่อยที่สุดคือเอาเปอร์เซ็นต์มา 'บวกลบกันตรงๆ' เช่น 500×(1−0.20+0.07)=500×0.87=435 ซึ่งผิด เพราะภาษีต้องคิดจากราคาหลังลดแล้ว ไม่ใช่ราคาเดิม — ต้องคูณต่อเนื่องทีละขั้นเสมอ"},{"q":"อัตราส่วนผสมคอนกรีต ปูนซีเมนต์:ทราย:หิน = 1:2:4 ถ้าใช้ปูนซีเมนต์ 3 ถุง ต้องใช้ทรายกี่ถุง (เพื่อคงอัตราส่วนเดิม)","choices":["6 ถุง","8 ถุง","4 ถุง","12 ถุง"],"correct":0,"hint":"อัตราส่วนผสมเป็นอัตราส่วนตรง (direct proportion) ปูนซีเมนต์เพิ่มกี่เท่า ทรายต้องเพิ่มเท่ากัน","steps":["อัตราส่วนเดิม ปูนซีเมนต์:ทราย = 1:2","ปูนซีเมนต์ใช้จริง 3 ถุง คือเพิ่มขึ้น 3 เท่าจากอัตราส่วน (1→3)","ทรายต้องเพิ่มขึ้น 3 เท่าเช่นกันเพื่อคงอัตราส่วน: 2×3 = 6 ถุง"],"tip":"อัตราส่วนผสม (เช่น คอนกรีต, น้ำยาเคมี, สูตรอาหาร) เป็นอัตราส่วนตรงเสมอ ต่างจากโจทย์ความเร็ว-เวลาหรือคน-วันที่มักเป็นอัตราส่วนผกผัน ต้องแยกให้ออกว่าโจทย์แบบใดเป็นแบบใด"},{"q":"ปั๊มน้ำ 3 เครื่อง (อัตราสูบเท่ากันทุกเครื่อง) สูบน้ำออกจากสระได้หมดใน 8 ชั่วโมง ถ้าใช้ปั๊มน้ำ 4 เครื่อง จะสูบน้ำออกหมดในกี่ชั่วโมง","choices":["6 ชั่วโมง","8 ชั่วโมง","10.67 ชั่วโมง","5 ชั่วโมง"],"correct":0,"hint":"ปริมาณงานรวม (จำนวนปั๊ม×เวลา) คงที่เสมอ เพราะน้ำในสระมีปริมาณเท่าเดิม — เป็นอัตราส่วนผกผัน","steps":["งานรวมคงที่: จำนวนปั๊ม1×เวลา1 = จำนวนปั๊ม2×เวลา2","แทนค่า 3×8 = 4×t2 → 24 = 4t2","จัดสมการ t2 = 24/4 = 6 ชั่วโมง"],"tip":"โจทย์แบบ 'จำนวนเครื่องจักร/คนงาน ↔ เวลาที่ใช้' เป็นอัตราส่วนผกผันเสมอ (ยิ่งมีคน/เครื่องมากยิ่งเสร็จเร็ว) จำสูตร n1×t1=n2×t2 ไว้ใช้ได้กับโจทย์แนวนี้ทุกแบบ"}]},
  {"id":"q_tpat3_sci4","subjectId":"tpat3","title":"TPAT3 · ความคิดเชิงวิศวกรรม: กระบวนการออกแบบ ชุดที่ 2","topic":"Scientific & Engineering Thinking (Design Process)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (ทดสอบต้นแบบ, ขั้นตอนแรกของกระบวนการออกแบบ, กลุ่มควบคุม) มาเป็นแนวคิดที่ลึกขึ้น: การวนซ้ำ (iteration) หลังพบข้อบกพร่อง, การแลกเปลี่ยน (trade-off) ระหว่างคุณสมบัติที่ขัดแย้งกัน, ความแตกต่างระหว่าง 'ข้อกำหนด' กับ 'เกณฑ์ความสำเร็จ', และเหตุผลที่ต้องระดมความคิดหลายแนวทางก่อนลงมือทำ","worked":{"q":"หลังจากทดสอบต้นแบบสะพานจำลองแล้วพบว่ารับน้ำหนักได้ไม่ถึงเกณฑ์ที่กำหนด ขั้นตอนถัดไปตามกระบวนการออกแบบเชิงวิศวกรรมคืออะไร","steps":["กระบวนการออกแบบเชิงวิศวกรรมเป็นวงจรที่วนซ้ำได้ (iterative) ไม่ใช่เส้นตรงทางเดียว","เมื่อทดสอบแล้วไม่ผ่านเกณฑ์ ต้องย้อนกลับไปปรับปรุงแก้ไขการออกแบบ (redesign)","จากนั้นวนกลับไปสร้างต้นแบบใหม่และทดสอบซ้ำ จนกว่าจะผ่านเกณฑ์ที่กำหนด"],"answer":"ปรับปรุง/ออกแบบใหม่แล้ววนกลับไปทดสอบซ้ำ"}},"questions":[{"q":"หลังจากทดสอบต้นแบบแล้วพบข้อบกพร่อง ขั้นตอนถัดไปตามกระบวนการออกแบบเชิงวิศวกรรมคืออะไร","choices":["ปรับปรุง/ออกแบบใหม่ (redesign) แล้ววนกลับไปทดสอบซ้ำ","หยุดโครงการทันที เพราะการออกแบบล้มเหลว","ผลิตจำนวนมากต่อไปโดยไม่ต้องแก้ไข","จดสิทธิบัตรทันทีก่อนที่คนอื่นจะคิดได้ก่อน"],"correct":0,"hint":"กระบวนการออกแบบเชิงวิศวกรรมเป็นวงจรที่วนซ้ำได้ ไม่ใช่เส้นตรงทางเดียวที่จบเมื่อทดสอบครั้งแรก","steps":["กระบวนการออกแบบเชิงวิศวกรรมเป็น iterative process (วนซ้ำได้)","เมื่อทดสอบแล้วพบข้อบกพร่อง ต้องปรับปรุงการออกแบบตามข้อมูลที่ได้จากการทดสอบ","วนกลับไปสร้างต้นแบบใหม่และทดสอบซ้ำ จนกว่าจะผ่านเกณฑ์ที่กำหนดไว้"],"tip":"ข้อบกพร่องที่พบจากการทดสอบไม่ใช่ 'ความล้มเหลว' แต่คือข้อมูลสำคัญที่ทำให้ปรับปรุงการออกแบบได้ดีขึ้น วิศวกรมืออาชีพคาดหวังให้ต้องวนซ้ำหลายรอบเป็นเรื่องปกติ"},{"q":"วิศวกรออกแบบแบตเตอรี่ต้องเลือกระหว่างความจุพลังงานสูงกับน้ำหนักเบา ถ้าเลือกออกแบบให้มีความจุพลังงานสูงสุด มักต้องแลกกับอะไร","choices":["น้ำหนักที่มากขึ้น","ไม่ต้องแลกกับอะไรเลย ได้ทั้งสองอย่างพร้อมกันเสมอ","ราคาที่ถูกลง","อายุการใช้งานที่สั้นลงเสมอโดยไม่มีข้อยกเว้น"],"correct":0,"hint":"การออกแบบวิศวกรรมมักมีคุณสมบัติที่ขัดแย้งกัน (trade-off) การได้อย่างหนึ่งมากขึ้นมักต้องเสียอีกอย่างหนึ่งไป","steps":["ความจุพลังงานที่สูงขึ้นมักต้องใช้วัสดุ/สารเคมีมากขึ้นภายในแบตเตอรี่","วัสดุที่มากขึ้นทำให้น้ำหนักโดยรวมของแบตเตอรี่เพิ่มขึ้นตามไปด้วย","นี่คือตัวอย่างของ trade-off ระหว่างคุณสมบัติสองอย่างที่ขัดแย้งกัน ซึ่งวิศวกรต้องชั่งน้ำหนักตามความต้องการใช้งานจริง"],"tip":"trade-off เป็นแนวคิดที่พบในการออกแบบวิศวกรรมแทบทุกชิ้นงาน (เช่น ความแข็งแรง vs น้ำหนัก, ความเร็ว vs ความประหยัดพลังงาน) โจทย์แนวนี้มักถามว่า 'ถ้าเลือกด้านหนึ่งมากขึ้น ต้องแลกกับอะไร' ให้คิดถึงทรัพยากรที่ต้องใช้เพิ่มเสมอ"},{"q":"ข้อกำหนด (constraints) กับเกณฑ์ความสำเร็จ (criteria) ในกระบวนการออกแบบเชิงวิศวกรรมต่างกันอย่างไร","choices":["constraints คือข้อจำกัดที่ต้องปฏิบัติตาม (เช่น งบประมาณ เวลา วัสดุ) ส่วน criteria คือมาตรฐานที่ใช้วัดความสำเร็จของงานออกแบบ","ทั้งสองคำมีความหมายเหมือนกันทุกประการ ใช้แทนกันได้เสมอ","constraints ใช้เฉพาะงานวิทยาศาสตร์ ส่วน criteria ใช้เฉพาะงานวิศวกรรมเท่านั้น","constraints คือเป้าหมายของโครงการ ส่วน criteria คือข้อจำกัดด้านงบประมาณ"],"correct":0,"hint":"ลองนึกถึงตัวอย่าง: 'ต้องใช้งบไม่เกิน 10,000 บาท' เป็นข้อจำกัดแบบหนึ่ง ส่วน 'ต้องรับน้ำหนักได้อย่างน้อย 5 กก.' เป็นมาตรฐานวัดความสำเร็จอีกแบบหนึ่ง — สองแบบนี้ต่างกันอย่างไร","steps":["constraints (ข้อจำกัด) คือเงื่อนไขที่การออกแบบต้องอยู่ภายใต้เสมอ เช่น งบประมาณ เวลา ขนาด วัสดุที่ใช้ได้","criteria (เกณฑ์ความสำเร็จ) คือมาตรฐานที่ใช้ตัดสินว่าการออกแบบนั้น 'ดี' หรือ 'สำเร็จ' หรือไม่ เช่น ต้องรับน้ำหนักได้เท่าไร ต้องทนทานกี่ปี","ทั้งสองอย่างจำเป็นต้องระบุให้ชัดเจนตั้งแต่ต้นกระบวนการออกแบบ เพื่อเป็นกรอบในการตัดสินใจตลอดโครงการ"],"tip":"วิธีจำง่ายๆ: constraints คือ 'สิ่งที่ห้ามทำเกิน/ต้องอยู่ภายใน' ส่วน criteria คือ 'สิ่งที่ต้องทำให้ถึง/ผ่านเกณฑ์' — คำถามข้อสอบจริงมักให้ยกตัวอย่างสถานการณ์แล้วให้แยกว่าข้อความไหนเป็นแบบไหน"},{"q":"เพราะเหตุใดกระบวนการออกแบบเชิงวิศวกรรมจึงเน้นให้ระดมความคิด (brainstorm) ออกแบบหลายแนวทางก่อนเลือกลงมือสร้างต้นแบบจริง","choices":["เพื่อเปรียบเทียบข้อดี-ข้อเสียของแต่ละแนวทาง ลดความเสี่ยงที่จะพลาดแนวทางที่ดีกว่าโดยไม่รู้ตัว","เพราะกฎหมายกำหนดให้ต้องมีอย่างน้อย 3 แนวทางเสมอ","เพื่อให้ใช้เวลาในโครงการนานขึ้นโดยไม่มีประโยชน์อื่น","เพราะต้นแบบแรกที่คิดได้มักผิดพลาดเสมอโดยไม่มีข้อยกเว้น"],"correct":0,"hint":"การสร้างต้นแบบจริงมีต้นทุนสูงทั้งเวลาและทรัพยากร การเปรียบเทียบแนวทางบนกระดาษก่อนจึงคุ้มค่ากว่า","steps":["การสร้างต้นแบบจริงแต่ละแนวทางมีต้นทุนสูง ทั้งเวลา วัสดุ และแรงงาน","การระดมความคิดหลายแนวทางก่อน ช่วยให้เปรียบเทียบข้อดี-ข้อเสียของแต่ละแนวทางได้โดยยังไม่ต้องลงทุนสร้างจริง","วิธีนี้ลดความเสี่ยงที่จะเลือกแนวทางแรกที่คิดได้ทั้งที่อาจมีแนวทางอื่นที่ดีกว่าซ่อนอยู่"],"tip":"หลักการนี้สะท้อนแนวคิด 'อย่ายึดติดกับไอเดียแรกที่คิดได้' ซึ่งเป็นหัวใจของกระบวนการออกแบบเชิงวิศวกรรมที่ดี ต่างจากการแก้ปัญหาแบบเดาสุ่มที่ไม่มีการเปรียบเทียบทางเลือกก่อน"}]},
  {"id":"q_tpat3_sci5","subjectId":"tpat3","title":"TPAT3 · ความคิดเชิงวิทยาศาสตร์: ทำนายผลการทดลอง ชุดที่ 2","topic":"Scientific Thinking (Predict Experimental Outcome)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (แรงโน้มถ่วงในสุญญากาศ, ความดันแก๊ส, คาบลูกตุ้ม, การแพร่ของสี) มาเป็นโจทย์ทำนายผลที่ครอบคลุมหลายสาขาวิชามากขึ้น รวมถึงโจทย์วงจรไฟฟ้าที่เชื่อมโยงโดยตรงกับกฎของโอห์ม — หัวใจของโจทย์แนวนี้คือการใช้หลักการทางวิทยาศาสตร์ที่รู้อยู่แล้วมาทำนายสถานการณ์ใหม่ที่ไม่เคยเจอมาก่อน","worked":{"q":"วงจรไฟฟ้าสองวงจรใช้แบตเตอรี่แรงดันเท่ากัน วงจร A มีความต้านทานรวมมากกว่าวงจร B (ต่อตัวต้านทานเพิ่มแบบอนุกรม) หลอดไฟในวงจรใดจะสว่างน้อยกว่า","steps":["ใช้กฎของโอห์ม I=V/R เมื่อแรงดัน V เท่ากัน กระแส I จะแปรผกผันกับความต้านทาน R","วงจร A มีความต้านทานรวมมากกว่า จึงมีกระแสไฟฟ้าไหลผ่านน้อยกว่าวงจร B","กระแสไฟฟ้าน้อยกว่าทำให้หลอดไฟในวงจร A สว่างน้อยกว่า"],"answer":"วงจร A สว่างน้อยกว่า"}},"questions":[{"q":"วงจรไฟฟ้าสองวงจรใช้แบตเตอรี่แรงดันเท่ากัน วงจร A มีความต้านทานรวมมากกว่าวงจร B (ต่อตัวต้านทานเพิ่มแบบอนุกรม) หลอดไฟในวงจรใดจะสว่างน้อยกว่า","choices":["วงจร A (เพราะความต้านทานมากกว่าทำให้กระแสไฟฟ้าไหลน้อยกว่าตามกฎของโอห์ม)","วงจร B (เพราะความต้านทานน้อยกว่าทำให้กระแสไฟฟ้าไหลน้อยกว่า)","สว่างเท่ากันทั้งสองวงจร เพราะแบตเตอรี่จ่ายแรงดันเท่ากัน","ไม่สามารถทำนายได้เพราะไม่ทราบชนิดของหลอดไฟ"],"correct":0,"hint":"ใช้กฎของโอห์ม I=V/R เมื่อแรงดันเท่ากัน กระแสจะแปรผกผันกับความต้านทาน","steps":["กฎของโอห์ม: I = V/R เมื่อ V เท่ากันทั้งสองวงจร","วงจร A มี R มากกว่า ดังนั้น I ของวงจร A จึงน้อยกว่า","กระแสน้อยกว่า = ความสว่างของหลอดไฟน้อยกว่า"],"tip":"หลักการนี้คือเหตุผลที่การต่อตัวต้านทานเพิ่มเข้าไปในวงจร (เช่น ในสวิตช์หรี่ไฟ) ทำให้หลอดไฟหรี่ลงได้ — ยิ่งต้านทานมาก กระแสยิ่งน้อย ความสว่างยิ่งลดลง"},{"q":"ช้อนโลหะกับช้อนไม้ (ความยาวเท่ากัน) จุ่มในซุปร้อนพร้อมกัน ด้ามช้อนอันใดจะร้อนเร็วกว่า","choices":["ช้อนโลหะ เพราะโลหะเป็นตัวนำความร้อนที่ดีกว่าไม้มาก","ช้อนไม้ เพราะไม้มีความหนาแน่นน้อยกว่า","ร้อนเร็วเท่ากันทั้งสองแบบ เพราะจุ่มในซุปอุณหภูมิเดียวกัน","ไม่มีอันใดร้อนขึ้นเลยเพราะด้ามช้อนอยู่นอกซุป"],"correct":0,"hint":"เปรียบเทียบสมบัติการนำความร้อน (thermal conductivity) ระหว่างโลหะกับไม้","steps":["ความร้อนถ่ายเทผ่านการนำความร้อน (conduction) จากปลายช้อนที่จุ่มในซุปไปยังด้ามจับ","โลหะมีสมบัตินำความร้อนดีกว่าไม้มาก (ไม้เป็นฉนวนความร้อนที่ดี)","ดังนั้นความร้อนจะถ่ายเทไปถึงด้ามช้อนโลหะเร็วกว่าด้ามช้อนไม้มาก"],"tip":"หลักการนี้คือเหตุผลที่ด้ามหม้อ กระทะ หรือช้อนตักอาหารร้อน มักทำจากไม้หรือพลาสติกทนความร้อน แทนที่จะเป็นโลหะล้วน เพื่อป้องกันไม่ให้มือร้อนตาม"},{"q":"แท่งแม่เหล็กหนึ่งแท่งถูกตัดออกเป็นสองท่อนตรงกลาง แต่ละท่อนจะมีขั้วแม่เหล็กอย่างไร","choices":["แต่ละท่อนมีขั้ว N และ S ครบทั้งสองขั้วเหมือนแม่เหล็กแท่งใหม่","ท่อนหนึ่งมีแต่ขั้ว N อีกท่อนมีแต่ขั้ว S","ทั้งสองท่อนสูญเสียสภาพแม่เหล็กไปทันที","ท่อนที่มีขนาดใหญ่กว่าจะแรงกว่า ท่อนเล็กจะไม่มีขั้วเลย"],"correct":0,"hint":"ในธรรมชาติไม่มี 'ขั้วแม่เหล็กเดี่ยว' (magnetic monopole) อยู่จริง แม่เหล็กทุกชิ้นต้องมีสองขั้วเสมอไม่ว่าจะเล็กแค่ไหน","steps":["สมบัติพื้นฐานของแม่เหล็กคือต้องมีขั้ว N และ S คู่กันเสมอ ไม่สามารถแยกขั้วเดี่ยวได้ (ไม่มี magnetic monopole ในธรรมชาติ)","เมื่อตัดแท่งแม่เหล็กออกเป็นสองท่อน แต่ละท่อนจะกลายเป็นแม่เหล็กแท่งใหม่ที่มีขั้ว N และ S ครบในตัวเอง","หากตัดต่อไปเรื่อยๆ แต่ละชิ้นก็ยังคงมีขั้วครบทั้งสองขั้วเสมอ ไม่ว่าจะเล็กเพียงใด"],"tip":"หลักการ 'ไม่มีขั้วแม่เหล็กเดี่ยว' นี้เป็นหนึ่งในกฎพื้นฐานที่สุดของแม่เหล็กไฟฟ้า ต่างจากประจุไฟฟ้าที่มีประจุบวกและลบแยกกันได้อิสระ"},{"q":"ลูกโป่งสองลูกขนาดเท่ากัน ลูกหนึ่งเติมแก๊สฮีเลียม อีกลูกเติมอากาศธรรมดา ปล่อยพร้อมกันในอากาศปกติ ลูกใดจะลอยขึ้น","choices":["ลูกที่เติมฮีเลียม เพราะฮีเลียมมีความหนาแน่นน้อยกว่าอากาศโดยรอบ","ลูกที่เติมอากาศธรรมดา เพราะอากาศมีน้ำหนักเบากว่า","ลอยขึ้นพร้อมกันทั้งสองลูก เพราะมีขนาดเท่ากัน","ไม่มีลูกใดลอยขึ้นเลยเพราะแรงโน้มถ่วงดึงดูดเท่ากัน"],"correct":0,"hint":"หลักการลอยตัวขึ้นอยู่กับการเปรียบเทียบความหนาแน่นของแก๊สภายในลูกโป่งกับความหนาแน่นของอากาศโดยรอบ","steps":["วัตถุ (รวมถึงลูกโป่งที่เติมแก๊ส) จะลอยขึ้นได้เมื่อความหนาแน่นเฉลี่ยน้อยกว่าความหนาแน่นของอากาศโดยรอบ","ฮีเลียมมีความหนาแน่นน้อยกว่าอากาศมาก (เบากว่าอากาศ) จึงทำให้ลูกโป่งลอยขึ้น","ลูกโป่งที่เติมอากาศธรรมดามีความหนาแน่นใกล้เคียงกับอากาศโดยรอบ (บวกน้ำหนักเปลือกลูกโป่ง) จึงไม่ลอยขึ้น"],"tip":"หลักการเดียวกันนี้อธิบายได้ทั้งลูกโป่งฮีเลียม เรือเหาะ และการลอยตัวของวัตถุในของไหลทุกชนิด — เปรียบเทียบความหนาแน่นเสมอ ไม่ใช่แค่น้ำหนัก"}]},
  {"id":"q_tpat3_news3","subjectId":"tpat3","title":"TPAT3 · ความรู้เทคโนโลยีปัจจุบัน ชุดที่ 2","topic":"Science & Tech Literacy (Current Technology)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (AI/Machine Learning, พลังงานหมุนเวียน, สารกึ่งตัวนำ, Cloud Computing) มาเป็นเทคโนโลยีที่เกี่ยวข้องโดยตรงกับวิศวกรรมไฟฟ้า-อิเล็กทรอนิกส์: เซลล์แสงอาทิตย์, แบตเตอรี่ลิเธียมไอออน, เครือข่าย 5G และ Internet of Things — ล้วนเป็นเทคโนโลยีที่นักศึกษาวิศวกรรมไฟฟ้าจะได้เจอโดยตรงในการเรียนและการทำงานจริง","worked":{"q":"เซลล์แสงอาทิตย์ (Solar Cell) เปลี่ยนพลังงานรูปแบบใดเป็นพลังงานไฟฟ้าโดยตรง และอาศัยหลักการใด","steps":["เซลล์แสงอาทิตย์ทำจากสารกึ่งตัวนำ (โดยทั่วไปคือซิลิคอน)","เมื่อแสงตกกระทบสารกึ่งตัวนำ จะเกิดปรากฏการณ์โฟโตวอลเทอิก (photovoltaic effect) ที่ทำให้อิเล็กตรอนหลุดออกและเกิดกระแสไฟฟ้า","ดังนั้นเซลล์แสงอาทิตย์เปลี่ยนพลังงานแสงเป็นพลังงานไฟฟ้าโดยตรง ไม่ต้องผ่านขั้นตอนกลไกใดๆ"],"answer":"พลังงานแสง ผ่านปรากฏการณ์โฟโตวอลเทอิกในสารกึ่งตัวนำ"}},"questions":[{"q":"เซลล์แสงอาทิตย์ (Solar Cell) เปลี่ยนพลังงานรูปแบบใดเป็นพลังงานไฟฟ้าโดยตรง และอาศัยหลักการใด","choices":["พลังงานแสง โดยอาศัยปรากฏการณ์โฟโตวอลเทอิก (photovoltaic effect) ในสารกึ่งตัวนำ","พลังงานลม โดยอาศัยการหมุนของใบพัด","พลังงานความร้อน โดยอาศัยการขยายตัวของโลหะ","พลังงานเคมี โดยอาศัยปฏิกิริยาออกซิเดชัน"],"correct":0,"hint":"เซลล์แสงอาทิตย์ทำจากสารกึ่งตัวนำ และแปลงพลังงานรูปแบบหนึ่งที่ตกกระทบพื้นผิวโดยตรง ไม่มีชิ้นส่วนเคลื่อนที่เลย","steps":["เซลล์แสงอาทิตย์ทำจากสารกึ่งตัวนำ (ซิลิคอน) ที่ถูกออกแบบให้ไวต่อแสง","เมื่อแสงตกกระทบ จะเกิดปรากฏการณ์โฟโตวอลเทอิก ทำให้อิเล็กตรอนหลุดออกจากอะตอมและเคลื่อนที่เป็นกระแสไฟฟ้า","กระบวนการนี้แปลงพลังงานแสงเป็นพลังงานไฟฟ้าโดยตรง ไม่ผ่านพลังงานกล (ต่างจากกังหันลมหรือกังหันไอน้ำ)"],"tip":"จุดสังเกตสำคัญคือเซลล์แสงอาทิตย์ไม่มีชิ้นส่วนเคลื่อนที่เลย ต่างจากพลังงานหมุนเวียนแบบอื่น (ลม น้ำ) ที่ต้องอาศัยการหมุนของกังหันไปขับเครื่องกำเนิดไฟฟ้าอีกทอดหนึ่ง"},{"q":"เหตุใดแบตเตอรี่ลิเธียมไอออน (Lithium-ion) จึงเป็นที่นิยมในรถยนต์ไฟฟ้าและอุปกรณ์อิเล็กทรอนิกส์พกพามากกว่าแบตเตอรี่แบบเก่า เช่น ตะกั่ว-กรด","choices":["ให้พลังงานต่อน้ำหนัก (energy density) สูงกว่ามาก จึงเก็บพลังงานได้มากในน้ำหนักที่เบากว่า","ราคาถูกกว่าตะกั่ว-กรดเสมอในทุกกรณี","ไม่มีวันเสื่อมสภาพเลยตลอดอายุการใช้งาน","ไม่ต้องมีระบบควบคุมการชาร์จเลย เพราะปลอดภัยในตัวเอง"],"correct":0,"hint":"เปรียบเทียบว่าถ้าต้องพกพาหรือติดตั้งในยานพาหนะ คุณสมบัติด้านน้ำหนักต่อพลังงานที่เก็บได้มีความสำคัญอย่างไร","steps":["ลิเธียมไอออนมีความหนาแน่นพลังงาน (energy density) สูงกว่าตะกั่ว-กรดมาก","สำหรับรถยนต์ไฟฟ้าและอุปกรณ์พกพา น้ำหนักที่เบากว่าในการเก็บพลังงานเท่ากันเป็นข้อได้เปรียบสำคัญมาก","นี่คือเหตุผลหลักที่อุตสาหกรรมเปลี่ยนมาใช้ลิเธียมไอออนแทนตะกั่ว-กรดในการใช้งานที่ต้องพกพาหรือเคลื่อนที่"],"tip":"แบตเตอรี่ตะกั่ว-กรดยังใช้อยู่ในรถยนต์สันดาปทั่วไป (สำหรับสตาร์ทเครื่องยนต์) เพราะราคาถูกและไม่ต้องการความหนาแน่นพลังงานสูง แต่รถยนต์ไฟฟ้าต้องการพลังงานมากในน้ำหนักน้อย จึงต้องใช้ลิเธียมไอออน"},{"q":"เทคโนโลยี 5G แตกต่างจาก 4G อย่างมีนัยสำคัญในด้านใดเป็นหลัก","choices":["ความเร็วในการรับส่งข้อมูลสูงกว่ามาก ความหน่วง (latency) ต่ำกว่ามาก และรองรับอุปกรณ์เชื่อมต่อพร้อมกันได้มากกว่า","ใช้คลื่นเสียงแทนคลื่นวิทยุในการส่งสัญญาณ","ทำงานได้เฉพาะกับโทรศัพท์มือถือรุ่นเก่าเท่านั้น","ไม่มีความแตกต่างจาก 4G เลยนอกจากชื่อเรียก"],"correct":0,"hint":"5G ถูกออกแบบมาเพื่อรองรับการใช้งานยุคใหม่ เช่น รถยนต์ไร้คนขับและอุปกรณ์ IoT จำนวนมาก ซึ่งต้องการอะไรเป็นพิเศษจากเครือข่าย","steps":["5G ใช้ย่านความถี่และเทคโนโลยีสัญญาณที่ทำให้ความเร็วรับส่งข้อมูลสูงกว่า 4G มาก","ความหน่วง (latency หรือเวลาตอบสนอง) ต่ำกว่ามาก ซึ่งสำคัญมากสำหรับงานที่ต้องการการตอบสนองทันที เช่น รถยนต์ไร้คนขับ","5G ยังรองรับจำนวนอุปกรณ์ที่เชื่อมต่อพร้อมกันในพื้นที่เดียวได้มากกว่า 4G มาก ทำให้รองรับ IoT ขนาดใหญ่ได้"],"tip":"เกณฑ์เปรียบเทียบเทคโนโลยีการสื่อสารไร้สายที่ควรจำคือ 3 ด้าน: ความเร็ว (bandwidth), ความหน่วง (latency), และจำนวนอุปกรณ์ที่รองรับพร้อมกัน (device density) — 5G ดีกว่า 4G ในทั้ง 3 ด้านนี้"},{"q":"Internet of Things (IoT) หมายถึงแนวคิดใดโดยพื้นฐาน","choices":["การเชื่อมต่ออุปกรณ์ต่างๆ (เช่น เครื่องใช้ไฟฟ้า เซนเซอร์) เข้ากับอินเทอร์เน็ต เพื่อให้สื่อสารและแลกเปลี่ยนข้อมูลกันได้โดยอัตโนมัติ","การเชื่อมต่อคอมพิวเตอร์หลายเครื่องเข้าด้วยกันในสำนักงานเดียว โดยไม่ผ่านอินเทอร์เน็ต","ระบบจัดเก็บไฟล์บนคลาวด์สำหรับองค์กรขนาดใหญ่เท่านั้น","มาตรฐานความปลอดภัยไซเบอร์สำหรับธนาคารออนไลน์"],"correct":0,"hint":"คำว่า 'Things' ในชื่อ IoT หมายถึงอุปกรณ์ทั่วไปในชีวิตประจำวัน ไม่ใช่แค่คอมพิวเตอร์หรือมือถือ","steps":["IoT คือแนวคิดการนำอุปกรณ์ทั่วไป (เครื่องใช้ไฟฟ้า เซนเซอร์ เครื่องจักร) มาติดตั้งชิปสื่อสารและเชื่อมต่อกับอินเทอร์เน็ต","อุปกรณ์เหล่านี้สามารถเก็บข้อมูล ส่งข้อมูล และรับคำสั่งได้โดยอัตโนมัติผ่านเครือข่าย","ตัวอย่างเช่น เซนเซอร์วัดอุณหภูมิในโรงงานที่ส่งข้อมูลไปยังระบบควบคุมกลางแบบเรียลไทม์ หรือเครื่องใช้ไฟฟ้าในบ้านที่สั่งงานผ่านมือถือได้"],"tip":"IoT เป็นสาขาที่เชื่อมโยงวิศวกรรมไฟฟ้า/อิเล็กทรอนิกส์ (เซนเซอร์ วงจร) เข้ากับวิศวกรรมคอมพิวเตอร์/ซอฟต์แวร์ (การสื่อสารข้อมูล) โดยตรง เป็นสาขาที่กำลังเติบโตเร็วมากในอุตสาหกรรม"}]},
  {"id":"q_tpat3_news4","subjectId":"tpat3","title":"TPAT3 · เหตุการณ์ประวัติศาสตร์วิทยาศาสตร์ ชุดที่ 2","topic":"Science & Tech Literacy (Historical Milestones)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (เพนิซิลลิน, โครงการจีโนมมนุษย์, สัมพัทธภาพทั่วไป, โทรศัพท์) มาเป็นเหตุการณ์ประวัติศาสตร์ที่เป็นรากฐานโดยตรงของวิศวกรรมไฟฟ้า: การค้นพบของฟาราเดย์ การประดิษฐ์ทรานซิสเตอร์ สงครามกระแสไฟฟ้า และสมการของแมกซ์เวลล์ — เป็นเหตุการณ์ประวัติศาสตร์ที่คงทนไม่ล้าสมัย (ต่างจากข่าวปัจจุบันที่รักษาความทันสมัยต่อเนื่องไม่ได้) และมีคุณค่าสูงเป็นพิเศษสำหรับผู้สนใจสายวิศวกรรมไฟฟ้า","worked":{"q":"ไมเคิล ฟาราเดย์ (Michael Faraday) ค้นพบปรากฏการณ์ใดที่เป็นรากฐานของเครื่องกำเนิดไฟฟ้าและหม้อแปลงไฟฟ้าสมัยใหม่","steps":["ฟาราเดย์ทดลองเคลื่อนแท่งแม่เหล็กผ่านขดลวดตัวนำ แล้วพบว่าเกิดกระแสไฟฟ้าไหลในขดลวดโดยไม่ต้องมีแบตเตอรี่เลย","ปรากฏการณ์นี้เรียกว่าการเหนี่ยวนำแม่เหล็กไฟฟ้า (electromagnetic induction)","หลักการนี้เป็นรากฐานที่เครื่องกำเนิดไฟฟ้า (generator) และหม้อแปลงไฟฟ้า (transformer) ทุกเครื่องในปัจจุบันใช้งาน"],"answer":"การเหนี่ยวนำแม่เหล็กไฟฟ้า (electromagnetic induction)"}},"questions":[{"q":"ไมเคิล ฟาราเดย์ (Michael Faraday) ค้นพบปรากฏการณ์ใดที่เป็นรากฐานของเครื่องกำเนิดไฟฟ้าและหม้อแปลงไฟฟ้าสมัยใหม่","choices":["การเหนี่ยวนำแม่เหล็กไฟฟ้า (electromagnetic induction) ซึ่งเป็นรากฐานของเครื่องกำเนิดไฟฟ้าและหม้อแปลงไฟฟ้า","ทฤษฎีสัมพัทธภาพ","กฎการเคลื่อนที่ของนิวตัน","โครงสร้างอะตอม"],"correct":0,"hint":"นึกถึงหลักการที่ทำให้เครื่องกำเนิดไฟฟ้าและหม้อแปลงไฟฟ้าทำงานได้ — เกี่ยวข้องกับการเคลื่อนที่สัมพัทธ์ระหว่างสนามแม่เหล็กกับขดลวด","steps":["ฟาราเดย์ทดลองเคลื่อนแท่งแม่เหล็กผ่านขดลวดตัวนำ พบว่าเกิดกระแสไฟฟ้าไหลโดยไม่ต้องมีแหล่งจ่ายไฟใดๆ","ปรากฏการณ์นี้เรียกว่าการเหนี่ยวนำแม่เหล็กไฟฟ้า","เครื่องกำเนิดไฟฟ้าในโรงไฟฟ้าทุกประเภท (พลังน้ำ ถ่านหิน นิวเคลียร์ ลม) และหม้อแปลงไฟฟ้าทุกเครื่อง ล้วนทำงานบนหลักการนี้"],"tip":"การเหนี่ยวนำแม่เหล็กไฟฟ้าของฟาราเดย์ (ค.ศ. 1831) ถือเป็นหนึ่งในการค้นพบที่ทรงอิทธิพลที่สุดในประวัติศาสตร์วิศวกรรมไฟฟ้า เพราะเป็นจุดเริ่มต้นของการผลิตไฟฟ้าขนาดใหญ่ที่มนุษย์ใช้กันทุกวันนี้"},{"q":"การประดิษฐ์ทรานซิสเตอร์ (Transistor) ที่ Bell Labs ในปี ค.ศ. 1947 มีความสำคัญอย่างไรต่อวงการอิเล็กทรอนิกส์","choices":["แทนที่หลอดสุญญากาศ ทำให้อุปกรณ์อิเล็กทรอนิกส์เล็กลง ประหยัดพลังงานกว่า เป็นรากฐานของคอมพิวเตอร์และไมโครชิปสมัยใหม่","เป็นอุปกรณ์แรกที่ใช้ผลิตกระแสไฟฟ้าจากพลังงานแสงอาทิตย์","เป็นจุดเริ่มต้นของอินเทอร์เน็ต","เป็นการค้นพบธาตุกัมมันตรังสีชนิดใหม่"],"correct":0,"hint":"ก่อนทรานซิสเตอร์ อุปกรณ์อิเล็กทรอนิกส์ใช้หลอดสุญญากาศซึ่งมีข้อเสียด้านขนาดและการใช้พลังงาน — ทรานซิสเตอร์แก้ปัญหานี้ได้อย่างไร","steps":["ก่อนหน้านี้วงจรอิเล็กทรอนิกส์ใช้หลอดสุญญากาศ (vacuum tube) ซึ่งมีขนาดใหญ่ ใช้พลังงานมาก และเสียง่าย","ทรานซิสเตอร์ (ทำจากสารกึ่งตัวนำ) ทำหน้าที่แทนหลอดสุญญากาศได้ แต่มีขนาดเล็กกว่ามาก ใช้พลังงานน้อยกว่า และทนทานกว่า","การย่อขนาดนี้เปิดทางให้เกิดวงจรรวม (integrated circuit) และไมโครชิปที่เป็นหัวใจของคอมพิวเตอร์และอุปกรณ์อิเล็กทรอนิกส์ทุกชนิดในปัจจุบัน"],"tip":"ทรานซิสเตอร์ถือเป็นหนึ่งในสิ่งประดิษฐ์ที่เปลี่ยนโลกมากที่สุดในศตวรรษที่ 20 เพราะเป็นจุดเริ่มต้นของยุคอิเล็กทรอนิกส์สมัยใหม่ทั้งหมด ตั้งแต่คอมพิวเตอร์ไปจนถึงสมาร์ทโฟน"},{"q":"สงครามกระแสไฟฟ้า (War of Currents) ระหว่างโทมัส เอดิสัน (สนับสนุนไฟฟ้ากระแสตรง DC) กับนิโคลา เทสลา/จอร์จ เวสติงเฮาส์ (สนับสนุนไฟฟ้ากระแสสลับ AC) จบลงด้วยผลอย่างไร","choices":["ระบบไฟฟ้ากระแสสลับ (AC) ชนะและกลายเป็นมาตรฐานการส่งไฟฟ้าทั่วโลก เพราะใช้หม้อแปลงปรับแรงดันส่งพลังงานระยะไกลได้อย่างมีประสิทธิภาพกว่า","ระบบไฟฟ้ากระแสตรง (DC) ชนะและยังคงเป็นมาตรฐานการส่งไฟฟ้าหลักจนถึงปัจจุบัน","ทั้งสองฝ่ายเลิกใช้ไฟฟ้าไปพร้อมกันแล้วหันไปใช้พลังงานไอน้ำแทน","ไม่มีฝ่ายใดชนะ เพราะไม่เคยมีการแข่งขันนี้เกิดขึ้นจริง"],"correct":0,"hint":"คิดถึงข้อได้เปรียบของ AC ที่เกี่ยวกับหม้อแปลงไฟฟ้า ซึ่งเป็นสิ่งที่ DC ทำไม่ได้ในยุคนั้น — ทำไมการส่งไฟฟ้าระยะไกลจึงสำคัญ","steps":["ไฟฟ้ากระแสสลับ (AC) สามารถใช้หม้อแปลงไฟฟ้าปรับแรงดันให้สูงขึ้นก่อนส่ง แล้วลดกลับลงตอนถึงปลายทางได้ ทำให้สูญเสียพลังงานระหว่างทางน้อยกว่ามาก","ไฟฟ้ากระแสตรง (DC) ในยุคนั้นยังไม่มีวิธีปรับแรงดันได้ง่ายเหมือน AC จึงส่งพลังงานได้ในระยะทางจำกัดกว่ามาก","ด้วยข้อได้เปรียบด้านการส่งพลังงานระยะไกลนี้ ระบบ AC จึงชนะและกลายเป็นมาตรฐานโครงข่ายไฟฟ้าทั่วโลกจนถึงปัจจุบัน"],"tip":"แม้ AC จะชนะสงครามกระแสไฟฟ้า แต่ DC ก็ยังสำคัญมากในปัจจุบัน (แบตเตอรี่ อุปกรณ์อิเล็กทรอนิกส์ แผงโซลาร์เซลล์ล้วนผลิต/ใช้ไฟ DC) ระบบไฟฟ้าสมัยใหม่จึงต้องมีวงจรแปลง AC-DC (rectifier) และ DC-AC (inverter) อยู่ทั่วไป"},{"q":"เจมส์ คลาร์ก แมกซ์เวลล์ (James Clerk Maxwell) มีผลงานสำคัญที่สุดคือการรวมทฤษฎีใดเข้าด้วยกันเป็นชุดสมการเดียว","choices":["ไฟฟ้า แม่เหล็ก และแสง เข้าด้วยกันเป็นทฤษฎีคลื่นแม่เหล็กไฟฟ้า (สมการของแมกซ์เวลล์)","กลศาสตร์ควอนตัมกับทฤษฎีสัมพัทธภาพ","เคมีอินทรีย์กับชีววิทยาโมเลกุล","ธรณีวิทยากับดาราศาสตร์"],"correct":0,"hint":"แมกซ์เวลล์แสดงให้เห็นว่าปรากฏการณ์ที่เคยคิดว่าไม่เกี่ยวข้องกัน 3 อย่างจริงๆ แล้วเป็นปรากฏการณ์เดียวกัน","steps":["ก่อนหน้าแมกซ์เวลล์ ไฟฟ้า แม่เหล็ก และแสง ถูกศึกษาแยกจากกันเป็นคนละสาขา","แมกซ์เวลล์เขียนสมการที่แสดงว่าสนามไฟฟ้าและสนามแม่เหล็กที่เปลี่ยนแปลงตามเวลาสามารถก่อให้เกิดกันและกันได้ แพร่กระจายเป็นคลื่นแม่เหล็กไฟฟ้า","แสงคือคลื่นแม่เหล็กไฟฟ้าชนิดหนึ่ง ทำให้ทฤษฎีทั้งสามเรื่องกลายเป็นเรื่องเดียวกัน นี่คือรากฐานของทฤษฎีคลื่นวิทยุ ไมโครเวฟ และการสื่อสารไร้สายทั้งหมดในปัจจุบัน"],"tip":"สมการของแมกซ์เวลล์ (Maxwell's Equations) ถือเป็นหนึ่งในความสำเร็จที่ยิ่งใหญ่ที่สุดของฟิสิกส์ศตวรรษที่ 19 และเป็นพื้นฐานทางทฤษฎีของวิศวกรรมไฟฟ้าสื่อสารสมัยใหม่ทั้งหมด ตั้งแต่วิทยุไปจนถึง 5G"}]}
);
